    always_ff @(posedge clk_in or posedge rst_in) begin
        if (rst_in) begin
            sync_word <= 2'b00;
        end else begin
            if (encoder_control_in == 8'b00000000) begin
                sync_word <= 2'b01;
            end else begin
                sync_word <= 2'b10;
