module serial_line_code_converter #(parameter CLK_DIV = 16)(
    input  logic clk,             // System clock
    input  logic reset_n,         // Active-low reset
    input  logic serial_in,       // Serial input signal
    input  logic [2:0] mode,      // Mode selector
    output logic serial_out       // Serial output signal
);

    // Internal signals
    logic [3:0] clk_counter;      // Clock divider counter
    logicclk_pulse;              // Clock pulse for sampling
    logic prev_serial_in;         // Previous serial input for edge detection
    logic prev_value;             // Holds the previous value of serial_in
    logic nrz_out;                // NRZ encoding output
    logic rz_out;                 // Return-to-Zero encoding output
    logic diff_out;               // Differential encoding output
    logic inv_nrz_out;            // Inverted NRZ output
    logic alt_invert_out;         // NRZ with alternating bit inversion output
    logic alt_invert_state;       // State for alternating inversion
    logic parity_out;             // Parity Bit Output
    logic scrambled_out;          // Scrambled NRZ output
    logic edge_triggered_out;     // Edge-Triggered NRZ output

    // Clock Pulse Generation
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            clk_counter <= 0;
            prev_serial_in <= 0;
        end else begin
            clk_counter <= clk_counter + 1;
            if (clk_counter == (CLK_DIV - 1)) begin
                clk_pulse <= 1;
                clk_counter <= 0;
            end
            prev_serial_in <= serial_in;
        end
    end

    // Return-to-Zero Encoding
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            rz_out <= 0;
        end else begin
            if (prev_serial_in == 0 && serial_in == 1) begin
                rz_out <= 1;
            else
                rz_out <= 0;
            end
        end
    end

    // Differential Encoding
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            diff_out <= 0;
        end else begin
            diff_out <= serial_in ^ prev_value;
        end
    end

    // Inverted NRZ Encoding
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            inv_nrz_out <= 0;
        end else begin
            inv_nrz_out <= ~serial_in;
        end
    end

    // NRZ with Alternating Bit Inversion
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            alt_invert_state <= 0;
            alt_invert_out <= 0;
        end else begin
            alt_invert_out <= serial_in ^ alt_invert_state;
            alt_invert_state <= ~alt_invert_state;
        end
    end

    // Parity Bit Output
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            parity_out <= 0;
        end else begin
            parity_out <= parity_out ^ serial_in;
        end
    end

    // Scrambled NRZ
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            scrambled_out <= 0;
        end else begin
            scrambled_out <= serial_in ^ (clk_counter & 1);
        end
    end

    // Edge-Triggered NRZ
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            edge_triggered_out <= 0;
        end else begin
            edge_triggered_out <= (serial_in & ~prev_serial_in);
        end
    end

    // Output Multiplexer
    always_ff @(posedge clk or negedge reset_n) begin
        if (mode == 0b000) begin
            serial_out <= nrz_out;
        elsif (mode == 0b001) begin
            serial_out <= rz_out;
        elsif (mode == 0b010) begin
            serial_out <= diff_out;
        elsif (mode == 0b011) begin
            serial_out <= inv_nrz_out;
        elsif (mode == 0b100) begin
            serial_out <= alt_invert_out;
        elsif (mode == 0b101) begin
            serial_out <= parity_out;
        elsif (mode == 0b110) begin
            serial_out <= scrambled_out;
        elsif (mode == 0b111) begin
            serial_out <= edge_triggered_out;
        else begin
            serial_out <= 0;
        end
    end
endmodule

module serial_line_code_converter #(parameter CLK_DIV = 16, parameter enable = 0)(
    input  logic clk,             // System clock
    input  logic reset_n,         // Active-low reset
    input  logic enable,          // Enable signal
    input  logic serial_in,       // Serial input signal
    input  logic [2:0] mode,      // Mode selector
    output logic serial_out       // Serial output signal
);

    // Internal signals
    logic [3:0]clk_counter;      // Clock divider counter
    logicclk_pulse;              // Clock pulse for sampling
    logic prev_serial_in;         // Previous serial input for edge detection
    logic prev_value;             // Holds the previous value of serial_in
    logic nrz_out;                // NRZ encoding output
    logic rz_out;                 // Return-to-Zero encoding output
    logic diff_out;               // Differential encoding output
    logic inv_nrz_out;            // Inverted NRZ output
    logic alt_invert_out;         // NRZ with alternating bit inversion output
    logic alt_invert_state;       // State for alternating inversion
    logic parity_out;             // Parity Bit Output
    logic scrambled_out;          // Scrambled NRZ output
    logic edge_triggered_out;     // Edge-Triggered NRZ output
    logic [16:0] diag_bus;        // Diagnostic output bus

    // Internal states
    logic [3:0] current_mode;     // Current encoding mode
    logic error_flag;             // Flag output indicating invalid input
    logic error_counter;           // Counts invalid input bits

    always_ff @(posedge clk or negedge reset_n or negedge enable) begin
        if (!reset_n && !enable) begin
            // Initialize all signals to default values
            clr all;
        end else if (enable) begin
            if (!reset_n) begin
                current_mode <= [2:0] '000;
                error_flag <= 0;
                error_counter <= 0;
            end else begin
                // Update current mode
                current_mode <= mode;

                // Update error state and counter
                if (serial_in == 1 && ( (mode & 8) == 1 || (mode & 4) == 1 )) begin
                    error_flag <= 1;
                    error_counter <= error_counter + 1;
                end

                // Other encoding logic remains the same
                // (NRZ, RZ, Differential, etc.)
                // ...
            end
        end else begin
            // Outputs are disabled
            serial_out <= 0;
            diag_bus <= 0;
            error_flag <= 0;
            error_counter <= 0;
        end
    end

    // Always comb logic for error detection
    always_comb begin
        case (mode)
            3'b000: serial_out = nrz_out;                
            3'b001: serial_out = rz_out;                 
            3'b010: serial_out = diff_out;               
            3'b011: serial_out = inv_nrz_out;            
            3'b100: serial_out = alt_invert_out;         
            3'b101: serial_out = parity_out;             
            3'b110: serial_out = scrambled_out;          
            3'b111: serial_out = edge_triggered_out;     
            default: serial_out = 0;                     
        endcase

        // Diagnostic output bus
        diag_bus <= [
            current_mode,
            error_flag,
            error_counter,
            (clk_pulse ? 1 : 0),
            serial_out,
            alt_invert_out
        ];
    end

    // Other existing code remains the same...

input.rtl/String_to_ASCII_Converter.sv:
module String_to_ASCII_Converter (
    input wire clk,                       // Clock signal
    input wire reset,                     // Reset signal
    input wire start,                     // Start conversion
    input wire [7:0] char_in [7:0],       // 8-character input string (7 bits per character: 0-95)
    output reg [7:0] ascii_out,           // Final latched ASCII output
    output reg valid,                     // Indicates valid output
    output reg ready                      // Indicates module ready to accept input
);
    // Parameters for character type identification
    localparam DIGIT   = 2'd0;
    localparam UPPER   = 2'd1;
    localparam LOWER   = 2'd2;
    localparam SPECIAL = 2'd3;
    // ASCII Offsets
    localparam DIGIT_OFFSET   = 8'd48;    // '0' = 48
    localparam UPPER_OFFSET   = 8'd65;    // 'A' = 65
    localparam LOWER_OFFSET   = 8'd97;    // 'a' = 97
    localparam SPECIAL_OFFSET = 8'd33;   // First special character '!' = 33
    // Registers
    reg [3:0] index;                      // Index for current character
    reg active;                           // Indicates active conversion
    reg [1:0] char_type;                  // Current character type
    reg [7:0] intermediate_ascii;         // Combinational ASCII value
    // Function to determine character type
    function [1:0] determine_char_type;
        input [7:0] char;
        begin
            if (char < 8'd10)
                determine_char_type = DIGIT;    // '0'-'9'
            else if (char < 8'd36)
                determine_char_type = UPPER;    // 'A'-'Z'
            else if (char < 8'd62)
                determine_char_type = LOWER;    // 'a'-'z'
            else
                determine_char_type = SPECIAL;  // Special characters
        end
    endfunction
    // Combinational logic for ASCII calculation
    always @(*) begin
        // Determine character type
        char_type = determine_char_type(char_in[index]);
        // Calculate ASCII based on character type
        case (char_type)
            DIGIT:   intermediate_ascii = char_in[index] + DIGIT_OFFSET;          // '0'-'9'
            UPPER:   intermediate_ascii = (char_in[index] - 8'd10) + UPPER_OFFSET; // 'A'-'Z'
            LOWER:   intermediate_ascii = (char_in[index] - 8'd36) + LOWER_OFFSET; // 'a'-'z'
            SPECIAL: intermediate_ascii = (char_in[index] - 8'd62) + SPECIAL_OFFSET; // Special characters
            default: intermediate_ascii = 8'd0;
        endcase
    end
    // Sequential logic
    always @(posedge clk or posedge reset) begin
        if (reset) begin
            index       <= 4'd0;
            ascii_out   <= 8'd0;
            valid       <= 1'b0;
            ready       <= 1'b1;
            active      <= 1'b0;
        end else begin
            if (start && ready) begin
                // Start conversion
                ready <= 1'b0;
                active <= 1'b1;
                index <= 4'd0;
                valid <= 1'b0;
            end else if (active) begin
                // Process current character
                if (index < 8) begin
                    ascii_out <= intermediate_ascii; // Latch current ASCII value
                    valid <= 1'b1; // Indicate valid output
                    index <= index + 1;
                end else begin
                    // Finish conversion
                    active <= 1'b0;
                    ready <= 1'b1;
                    valid <= 1'b0;
                end
            end
        end
    end
endmodule

output.rtl/sync_muller_c_element.sv:
module sync_muller_c_element #(
  parameter NUM_INPUT  = 2,
  parameter PIPE_DEPTH = 1
) (
  input  logic                  clk,
  input  logic                  srst,
  input  logic                  clr,
  input  logic                  clk_en,
  input  logic  [NUM_INPUT-1:0] inp,
  output logic                  out
);

  logic [(PIPE_DEPTH*NUM_INPUT)-1:0] pipe;
  genvar i;

  generate
    if (i == 0)
      pipe[0] = inp;
    else
      pipe[i] = pipe[i-1];
    endcase
  endgenerate

  if (srst || clr)
    pipe = 0;
    out = 0;
  else if (clk_en)
    if (pipe[PIPE_DEPTH*NUM_INPUT-1] == 0)
      out = 0;
    else
      out = 1;
    endcase
  else
    out = out;
  endcase
endmodule

output.rtl/adc_data_rotate.sv:
module adc_data_rotate #(
    parameter DATA_WIDTH = 8
)(
    input logic i_clk,
    input logic i_rst_n,
    input logic [DATA_WIDTH-1:0] i_adc_data_in,
    input logic [3:0] i_shift_count,
    input logic i_shift_direction,
    output logic [DATA_WIDTH-1:0] o_processed_data,
    output logic o_operation_status
);

    // Reset handling
    if (i_rst_n) begin
        o_operation_status = 0;
        o_processed_data = 0;
        // Wait for next clock cycle to reset
        wait;
    end else begin
        // Only perform rotation when reset is inactive
        case (i_shift_direction)
        // Left rotate
        0: begin
            // Calculate effective shift count
            shift_count = i_shift_count % DATA_WIDTH;
            if (shift_count == 0) begin
                o_processed_data = i_adc_data_in;
            else
                o_processed_data = (i_adc_data_in << shift_count) | (i_adc_data_in >> (DATA_WIDTH - shift_count));
            end
            o_operation_status = 1;
        end // Left rotate
        // Right rotate
        1: begin
            // Calculate effective shift count
            shift_count = i_shift_count % DATA_WIDTH;
            if (shift_count == 0) begin
                o_processed_data = i_adc_data_in;
            else
                o_processed_data = (i_adc_data_in >> shift_count) | ((i_adc_data_in << (DATA_WIDTH - shift_count)) >> (DATA_WIDTH - 1));
            end
            o_operation_status = 1;
        end // Right rotate
    end

endmodule

input.rtl/key_expansion_128aes.sv:
module key_expansion_128aes #(
    parameter NBW_KEY = 'd128,
    parameter NBW_OUT = 'd1408
) (
    input  logic               clk,
    input  logic               rst_async_n,
    input  logic               i_start,
    input  logic [NBW_KEY-1:0] i_key,
    output logic               o_done,
    output logic [NBW_OUT-1:0] o_expanded_key
);

localparam NBW_BYTE = 'd8;
localparam STEPS = 'd10;
localparam NBW_WORD = 'd32;

// Auxiliary wires
logic [NBW_BYTE-1:0] Rcon   [STEPS];
logic [NBW_KEY-1:0] valid_key;
logic [NBW_KEY-1:0] step_key[STEPS];
logic [NBW_OUT-1:0] expanded_key_nx;
logic [NBW_OUT-1:0] expanded_key_ff;

logic [STEPS:0] steps_ff;

logic [3:0] count_ff;
logic [3:0] count_nx;

always_ff @(posedge clk or negedge rst_async_n) begin : reset_regs
    if(~rst_async_n) begin
        expanded_key_ff <= {NBW_OUT{1'b0}};
        steps_ff <= 11'h400;
    end else begin
        expanded_key_ff <= expanded_key_nx;
        if(i_start || (|steps_ff[9:0])) begin
            steps_ff <= {steps_ff[STEPS-1:0], (i_start & o_done)};
        end
    end
end

assign o_done = steps_ff[STEPS];
assign o_expanded_key = expanded_key_ff;

assign Rcon[0] = 8'h01;
assign Rcon[1] = 8'h02;
assign Rcon[2] = 8'h04;
assign Rcon[3] = 8'h08;
assign Rcon[4] = 8'h10;
assign Rcon[5] = 8'h20;
assign Rcon[6] = 8'h40;
assign Rcon[7] = 8'h80;
assign Rcon[8] = 8'h1b;
assign Rcon[9] = 8'h36;

generate
    for(genvar i = 0; i < STEPS; i++) begin : steps
        logic [NBW_WORD-1:0] RotWord;
        logic [NBW_WORD-1:0] SubWord;
        logic [NBW_WORD-1:0] RconXor;

        sbox uu_sbox0 (
            .i_data(RotWord[31:24]),
            .o_data(SubWord[31:24])
        );

        sbox uu_sbox1 (
            .i_data(RotWord[23:16]),
            .o_data(SubWord[23:16])
        );

        sbox uu_sbox2 (
            .i_data(RotWord[15:8]),
            .o_data(SubWord[15:8])
        );

        sbox uu_sbox3 (
            .i_data(RotWord[7:0]),
            .o_data(SubWord[7:0])
        );

        always_comb begin
            RotWord = {expanded_key_ff[NBW_OUT-(i+1)*NBW_KEY+NBW_WORD-NBW_BYTE-1-:(NBW_WORD-NBW_BYTE)], expanded_key_ff[NBW_OUT-(i+1)*NBW_KEY+NBW_WORD-1-:NBW_BYTE]};
            RconXor = {SubWord[31:24]^Rcon[i], SubWord[23:0]};

            step_key[i][127:96] = expanded_key_ff[NBW_OUT-(4*i  )*NBW_WORD-1-:NBW_WORD] ^ RconXor;
            step_key[i][95 :64] = expanded_key_ff[NBW_OUT-(4*i+1)*NBW_WORD-1-:NBW_WORD] ^ step_key[i][127:96];
            step_key[i][63 :32] = expanded_key_ff[NBW_OUT-(4*i+2)*NBW_WORD-1-:NBW_WORD] ^ step_key[i][95 :64];
            step_key[i][31 :0 ] = expanded_key_ff[NBW_OUT-(4*i+3)*NBW_WORD-1-:NBW_WORD] ^ step_key[i][63 :32];
        end
    end
endgenerate

assign expanded_key_nx = {valid_key  , step_key[0], step_key[1], step_key[2],
                          step_key[3], step_key[4], step_key[5], step_key[6],
                          step_key[7], step_key[8], step_key[9]};

always_comb begin
    if (i_start & o_done) begin
        valid_key = i_key;
    end else begin
        valid_key = expanded_key_ff[NBW_OUT-1-:NBW_KEY];
    end
end

endmodule : key_expansion_128aes

