module axi_tap #(
    parameter ADDR_WIDTH = 32,
    parameter DATA_WIDTH = 32,
    parameter TIMEOUT_THRESHOLD = 1000 // configurable timeout
)(
    // Global Ports
    input           clk_i,
    input           rst_i,

    // Master Write Address Channel (AW)
    input           inport_awvalid_i,
    input  [ADDR_WIDTH-1:0]   inport_awaddr_i,
    output          inport_awready_o,
    // Master Write Data Channel (W)
    input           inport_wvalid_i,
    input  [DATA_WIDTH-1:0]   inport_wdata_i,
    input  [3:0]    inport_wstrb_i,
    output          inport_wready_o,
    // Master Write Response Channel (B)
    input           inport_bready_i,
    output          inport_bvalid_o,
    output [1:0]    inport_bresp_o,
    // Master Read Address Channel (AR)
    input           inport_arvalid_i,
    input           inport_araddr_i,
    output          inport_arready_o,
    // Master Read Data Channel (R)
    input           inport_rready_i,
    output          inport_rvalid_o,
    output [DATA_WIDTH-1:0]   inport_rdata_o,
    output [1:0]    inport_rresp_o,

    // Peripheral 0 interface
    // Write Address Channel (AW)
    input           outport_peripheral0_awready_i,
    output          outport_peripheral0_awvalid_o,
    output [ADDR_WIDTH-1:0]   outport_peripheral0_awaddr_o,
    // Write Data Channel (W)
    input           outport_peripheral0_wready_i,
    output          outport_peripheral0_wvalid_o,
    output [DATA_WIDTH-1:0]   outport_peripheral0_wdata_o,
    output [3:0]    outport_peripheral0_wstrb_o,
    // Write Response Channel (B)
    input           outport_peripheral0_bready_i,
    output          outport_peripheral0_bvalid_o,
    output [1:0]    outport_peripheral0_bresp_o,
    // Read Address Channel (AR)
    input           outport_peripheral0_arready_i,
    output          outport_peripheral0_arvalid_o,
    output [ADDR_WIDTH-1:0]   outport_peripheral0_araddr_o,
    // Read Data Channel (R)
    input           outport_peripheral0_rready_i,
    output          outport_peripheral0_rvalid_o,
    input  [DATA_WIDTH-1:0]   outport_peripheral0_rdata_i,
    input  [1:0]    outport_peripheral0_rresp_i,
    // Default AXI outport
    // Write Address Channel (AW)
    input           outport_awready_i,
    output          outport_awvalid_o,
    output [ADDR_WIDTH-1:0]   outport_awaddr_o,
    // Write Data Channel (W)
    input           outport_wready_i,
    output          outport_wvalid_o,
    output [DATA_WIDTH-1:0]   outport_wdata_o,
    output [3:0]    outport_wstrb_o,
    // Write Response Channel (B)
    input           outport_bvalid_i,
    input  [1:0]    outport_bresp_i,
    output          outport_bready_o,

    // Timeout-related variables
    reg [4'b0111] timeout_read_timer; // 4-bit counter for read timeout
    reg [4'b0111] timeout_write_timer; // 4-bit counter for write timeout
    reg timeout_flag = 0; // Timeout detection flag
    reg [4'b0000] timeout_read_state; // State of read timeout
    reg [4'b0000] timeout_write_state; // State of write timeout

    // Always blocks for timeout detection
    always @ (posedge clk_i)
    begin
        // Read timeout detection
        if (inport_arvalid_i && inport_araddr_i == PERIPH0_ADDR) 
            timeout_read_timer = timeout_read_timer + 1;
        else 
            timeout_read_timer = 0;
        end

        if (timeout_read_timer >= TIMEOUT_THRESHOLD)
            timeout_flag = 1;
        end

        // Write timeout detection
        if (inport_awvalid_i && inport_awaddr_i == PERIPH0_ADDR) 
            timeout_write_timer = timeout_write_timer + 1;
        else 
            timeout_write_timer = 0;
        end

        if (timeout_write_timer >= TIMEOUT_THRESHOLD)
            timeout_flag = 1;
        end
    end

    // Error handling for timeout
    always @ (posedge clk_i)
    begin
        case (timeout_flag)
            1:
                // Handle timeout here
                // Example: Abort transaction
                inport_arvalid_i = 0;
                inport_araddr_i = 0;
                inport_rvalid_o = 0;
                inport_rdata_o = 0;
                inport_rresp_o = 0;
                timeout_flag = 0;
                break;
    end
endmodule

output.rtl/precision_counter_axi.sv:
Module for precision_counter_axi implementation
module precision_counter_axi (
    input axi_aclk,
    input axi_aresetn,
    input [C_S_AXI_ADDR_WIDTH-1:0] axi_awaddr,
    input [C_S_AXI_DATA_WIDTH-1:0] axi_wdata,
    input [(C_S_AXI_DATA_WIDTH/8)-1:0] axi_wstrb,
    input [C_S_AXI_ADDR_WIDTH-1:0] axi_araddr,
    input axi_arvalid,
    input axi_wvalid,
    input axi_bvalid,
    input axi_rvalid,
    output axi_awready,
    output axi_wready,
    output axi_bresp,
    output axi_rresp,
    output axi_ap_done,
    output wire irq
);

// Parameters
parameter C_S_AXI_DATA_WIDTH = 32;
parameter C_S_AXI_ADDR_WIDTH = 8;

// Internal registers
reg [C_S_AXI_DATA_WIDTH-1:0] slv_reg_ctl = 0;
reg [C_S_AXI_DATA_WIDTH-1:0] slv_reg_t = 0;
reg [C_S_AXI_DATA_WIDTH-1:0] slv_reg_v = 0;
reg [C_S_AXI_DATA_WIDTH-1:0] slv_reg_irq_mask = 0;
reg [C_S_AXI_DATA_WIDTH-1:0] slv_reg_irq_thresh = 0;

// Start/Stop control
always @(posedge axi_aclk) begin
    if (axi_aresetn) begin
        slv_reg_ctl = 0;
        slv_reg_t = 0;
        slv_reg_v = 0;
    end else if (axi_arvalid) begin
        if (slv_reg_v == 0) begin
            slv_reg_t = 0;
        end else if (slv_reg_v > 0) begin
            slv_reg_t = slv_reg_t + 1;
            slv_reg_v = slv_reg_v - 1;
        end
    end
end

// Interrupt handling
always @(axi_aclk) begin
    if (axi_aresetn) begin
        slv_reg_irq_mask = 0;
        slv_reg_irq_thresh = 0;
    end else if (axi_rvalid && (slv_reg_v == slv_reg_irq_thresh)) begin
        if (slv_reg_irq_mask & 0x00000001) begin
            irq = 1;
        end
        slv_reg_irq_thresh = slv_reg_irq_thresh + 1;
    end
end

// Write transaction
always @(posedge axi_aclk) begin
    if (axi_aresetn) begin
        slv_reg_awvalid = 0;
    end else if (axi_awvalid) begin
        if (axi_arvalid) begin
            if (slv_reg_wvalid) begin
                if (slv_reg_awready) begin
                    slv_reg_bvalid = 1;
                    slv_reg_arvalid = 1;
                end
            end
        end
    end
end

// Read transaction
always @(posedge axi_aclk) begin
    if (axi_aresetn) begin
        slv_reg_arvalid = 0;
    end else if (axi_arvalid) begin
        if (slv_reg_rvalid) begin
            if (slv_reg_rready) begin
                slv_reg_rvalid = 1;
                slv_reg_arvalid = 1;
            end
        end
    end
end

// Register outputs
wire [C_S_AXI_DATA_WIDTH-1:0] slv_reg_awdata;
wire [C_S_AXI_DATA_WIDTH-1:0] slv_reg_wdata;
wire [C_S_AXI_DATA_WIDTH/8-1:0] slv_reg_wstrb;

endmodule

output.rtl/axis_image_border_gen.sv:
module axis_image_border_gen #(
    parameter IMG_WIDTH  = 336,
    parameter IMG_HEIGHT = 256,
    parameter BORDER_COLOR = 16'hFFFF,
    parameter DATA_MASK    = 16'h0000
)(
    input  wire            clk,
    input  wire            resetn,
    input  wire [15:0]     s_axis_tdata,
    input  wire            s_axis_tvalid,
    input  wire            s_axis_tlast,
    input  wire            s_axis_tuser,
    output wire [15:0]     m_axis_tdata,
    output wire            m_axis_tvalid,
    output wire            m_axis_tlast,
    input  wire            m_axis_tready,
    output wire            m_axis_tuser
);

    // State and Counter Registers
    reg [2:0] state, next_state;
    reg [15:0] x_count, y_count;
    reg border_valid;

    // Internal Control Signals
    wire is_top_row     = (y_count == 16'd0);
    wire is_bottom_row  = (y_count == IMG_HEIGHT + 1);
    wire is_left_border  = (x_count == 16'd0);
    wire is_right_border = (x_count == IMG_WIDTH + 1);
    wire is_border_pixel = (is_top_row || is_bottom_row || is_left_border || is_right_border);

    // FSM and Counter Logic
    always @(posedge clk or negedge resetn) begin
        if (!resetn) begin
            state = ST_IDLE;
            next_state = ST_IDLE;
        else begin
            case (state)
                ST_IDLE: begin
                    if (s_axis_tuser) begin
                        state = ST_ROW_FIRST;
                        next_state = ST_ROW_FIRST;
                    end else begin
                        state = ST_IDLE;
                        next_state = ST_IDLE;
                    end
                end

                ST_ROW_FIRST: begin
                    if (s_axis_tuser) begin
                        state = ST_PROCESS_ROW;
                        next_state = ST_PROCESS_ROW;
                    end else begin
                        state = ST_ROW_FIRST;
                        next_state = ST_ROW_FIRST;
                    end
                end

                ST_PROCESS_ROW: begin
                    if (is_border_pixel) begin
                        border_valid = 1;
                    end else begin
                        border_valid = 0;
                    end

                    if (s_axis_tvalid) begin
                        if (border_valid) begin
                            m_axis_tdata = (s_axis_tdata & DATA_MASK) | BORDER_COLOR;
                            m_axis_tvalid = 1;
                        else begin
                            m_axis_tdata = s_axis_tdata & DATA_MASK;
                            m_axis_tvalid = 1;
                        end
                        if (s_axis_tlast) begin
                            m_axis_tlast = 1;
                            m_axis_tuser = 1;
                            m_axis_tready = 1;
                        else begin
                            m_axis_tready = 0;
                        end
                    end else begin
                        m_axis_tvalid = 0;
                        m_axis_tready = 0;
                    end

                    if (y_count == IMG_HEIGHT) begin
                        state = ST_BORDER_ROW;
                        next_state = ST_BORDER_ROW;
                    end else begin
                        x_count = x_count + 1;
                        y_count = y_count + 1;
                        state = ST_PROCESS_ROW;
                        next_state = ST_PROCESS_ROW;
                    end
                end

                ST_BORDER_ROW: begin
                    border_valid = 1;
                    if (s_axis_tvalid) begin
                        m_axis_tdata = (s_axis_tdata & DATA_MASK) | BORDER_COLOR;
                        m_axis_tvalid = 1;
                    else begin
                        m_axis_tvalid = 0;
                    end
                    if (s_axis_tlast) begin
                        m_axis_tlast = 1;
                        m_axis_tuser = 1;
                        m_axis_tready = 1;
                    else begin
                        m_axis_tready = 0;
                    end
                    state = ST_ROW_LAST;
                    next_state = ST_ROW_LAST;
                end

                ST_ROW_LAST: begin
                    state = ST_IDLE;
                    next_state = ST_IDLE;
                end
            end
        end
    end

    // Initialize counters and state
    state = ST_IDLE;
    next_state = ST_IDLE;
    x_count = 16'd0;
    y_count = 16'd0;
    border_valid = 0;

    // Output data valid handling
    wire begin
        if (m_axis_tvalid) begin
            // Handle data transfer
        end
    end
endmodule

