output.rtl/barrel_shifter.sv:
module barrel_shifter(input [(data_width - 1):0] data_in, input [shift_bits_width - 1:0] shift_bits, input left_right, input rotate_left_right, output [(data_width - 1):0] data_out);
    assign if (shift_bits == 0) then
        data_out = data_in;
    else
        if (left_right) then
            if (rotate_left_right) then
                // Left rotate
                data_out = (data_in << shift_bits) | (data_in >> (data_width - shift_bits));
            else
                // Left shift
                data_out = data_in << shift_bits;
        else
            if (rotate_left_right) then
                // Right rotate
                data_out = (data_in >> shift_bits) | (data_in << (data_width - shift_bits));
            else
                // Right shift
                data_out = data_in >> shift_bits;
    endmodule

input.rtl/barrel_shifter.sv:
module barrel_shifter #(
    parameter data_width = 16,      // Change data_width to 16
    parameter shift_bits_width = 4  // Update shift_bits_width to handle shifts for 16-bit width
)(
    input [data_width-1:0] data_in,
    input [shift_bits_width-1:0] shift_bits,
    input left_right,               // 1: left shift, 0: right shift
    input rotate_left_right,        // 1: rotate, 0: shift
    input arithmetic_shift,         // 1: arithmetic shift, 0: logical shift
    output reg [data_width-1:0] data_out
);

always @(*) begin
    if (rotate_left_right) begin
        // Rotation logic
        if (left_right)
            data_out = (data_in << shift_bits) | (data_in >> (data_width - shift_bits)); // Rotate left
        else
            data_out = (data_in >> shift_bits) | (data_in << (data_width - shift_bits)); // Rotate right
    end else begin
        // Shift logic
        if (left_right)
            data_out = data_in << shift_bits;  // Left shift
        else if (arithmetic_shift)
            // Arithmetic right shift: explicitly sign-extend data_in to ensure the MSB (sign bit) is preserved
            data_out = $signed(data_in) >>> shift_bits;
        else
            data_out = data_in >> shift_bits;  // Logical right shift
    end
end

endmodule

output.rtl/barrel_shifter.sv:
module barrel_shifter #(
    parameter data_width = 16,
    parameter shift_bits_width = 4,
    parameter mask_width = data_width  // Derived from data_width
)(
    input [data_width-1:0] data_in,
    input [shift_bits_width-1:0] shift_bits,
    input [mask_width-1:0] mask,  // Additional mask input for mode 011 and 100
    input left_right,
    input rotate_left_right,
    input arithmetic_shift,
    input mode,
    output reg [data_width-1:0] data_out,
    output reg error
);

always @(*) begin
    if (mode == 000) begin
        // Logical shift
        if (left_right)
            data_out = data_in << shift_bits;
        else
            data_out = data_in >> shift_bits;
    else if (mode == 001) begin
        // Arithmetic shift with sign extension
        data_out = $signed(data_in) >>> shift_bits;
    else if (mode == 010) begin
        // Rotate
        if (left_right)
            data_out = (data_in << shift_bits) | (data_in >> (data_width - shift_bits));
        else
            data_out = (data_in >> shift_bits) | (data_in << (data_width - shift_bits));
    else if (mode == 011) begin
        // Masked shift
        if (left_right)
            data_out = (data_in << shift_bits) & mask;
        else
            data_out = (data_in >> shift_bits) & mask;
    else if (mode == 100) begin
        // XOR with shifted data and mask
        if (left_right)
            data_out = (data_in << shift_bits) ^ mask;
        else
            data_out = (data_in >> shift_bits) ^ mask;
