module binary_search_tree_sort #(
    parameter DATA_WIDTH = 32,
    parameter ARRAY_SIZE = 8
) (
    input clk,
    input reset,
    input reg [ARRAY_SIZE*DATA_WIDTH-1:0] data_in,
    input start,
    output reg [ARRAY_SIZE*DATA_WIDTH-1:0] sorted_out,
    output reg done
);

    // Parameters for top-level FSM states
    parameter IDLE = 2'b00, BUILD_TREE = 2'b01, SORT_TREE = 2'b10;

    // FSM states
    reg [1:0] top_state, build_state, sort_state;

    // BST representation
    reg [ARRAY_SIZE*DATA_WIDTH-1:0] keys;
    reg [ARRAY_SIZE*($clog2(ARRAY_SIZE)+1)-1:0] left_child;
    reg [ARRAY_SIZE*($clog2(ARRAY_SIZE)+1)-1:0] right_child;
    reg [$clog2(ARRAY_SIZE):0] root;
    reg [$clog2(ARRAY_SIZE):0] next_free_node;
    reg [$clog2(ARRAY_SIZE):0] current_node;
    reg [$clog2(ARRAY_SIZE):0] input_index;
    reg [$clog2(ARRAY_SIZE):0] output_index;
    reg [DATA_WIDTH-1:0] temp_data;

    // Stack for traversal
    reg [ARRAY_SIZE*($clog2(ARRAY_SIZE)+1)-1:0] stack;
    reg [$clog2(ARRAY_SIZE):0] sp;

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            top_state <= IDLE;
            build_state <= INIT;
            sort_state <= S_INIT;

            root <= {($clog2(ARRAY_SIZE)+1){1'b1}};
            next_free_node <= 0;
            sp <= 0;
            input_index <= 0;
            output_index <= 0;
            done <= 0;

            for (i = 0; i < ARRAY_SIZE; i = i + 1) begin
                keys[i*DATA_WIDTH +: DATA_WIDTH] <= 0;
                left_child[i*($clog2(ARRAY_SIZE)+1) +: ($clog2(ARRAY_SIZE)+1)] <= {($clog2(ARRAY_SIZE)+1){1'b1}};
                right_child[i*($clog2(ARRAY_SIZE)+1) +: ($clog2(ARRAY_SIZE)+1)] <= {($clog2(ARRAY_SIZE)+1){1'b1}};
                stack[i*($clog2(ARRAY_SIZE)+1) +: ($clog2(ARRAY_SIZE)+1)] <= {($clog2(ARRAY_SIZE)+1){1'b1}};
            end
        end else begin
            case (top_state)
                IDLE: begin
                    done <= 0;
                    input_index <= 0;
                    output_index <= 0;
                    root <= {($clog2(ARRAY_SIZE)+1){1'b1}};
                    next_free_node <= 0;
                    sp <= 0;

                    for (i = 0; i < ARRAY_SIZE+1; i = i + 1) begin
                        keys[i*DATA_WIDTH +: DATA_WIDTH] <= 0;
                        left_child[i*($clog2(ARRAY_SIZE)+1) +: ($clog2(ARRAY_SIZE)+1)] <= {($clog2(ARRAY_SIZE)+1){1'b1}};
                        right_child[i*($clog2(ARRAY_SIZE)+1) +: ($clog2(ARRAY_SIZE)+1)] <= {($clog2(ARRAY_SIZE)+1){1'b1}};
                        stack[i*($clog2(ARRAY_SIZE)+1) +: ($clog2(ARRAY_SIZE)+1)] <= {($clog2(ARRAY_SIZE)+1){1'b1}};
                    end
                    if (start) begin
                        top_state <= BUILD_TREE;
                        build_state <= INIT;
                    end
                end

                BUILD_TREE: begin
                    case (build_state)
                        INIT: begin
                            temp_data <= data_in[input_index];
                            input_index <= input_index + 1;

                            if (input_index > ARRAY_SIZE) begin
                                next_free_node <= root;
                                root <= next_free_node;
                                build_state <= COMPLETE;
                            end else begin
                                if (left_child[root] == 0) begin
                                    right_child[root] <= temp_data;
                                    current_node <= right_child[root];
                                    build_state <= INSERT;
                                end else begin
                                    current_node <= left_child[root];
                                    while (left_child[current_node] != 0) begin
                                        current_node <= left_child[current_node];
                                    end
                                    if (left_child[current_node] == 0) begin
                                        left_child[current_node] <= temp_data;
                                        build_state <= INSERT;
                                    else begin
                                        temp_data <= right_child[current_node];
                                        current_node <= right_child[current_node];
                                    end
                                    end
                                end
                            end
                        end
                end

                SORT_TREE: begin
                    case (sort_state)
                        S_INIT: begin
                            stack <= root;
                            sp <= 0;
                            output_index <= 0;

                            while (sp < $clog2(ARRAY_SIZE)) begin
                                current_node <= stack[sp];
                                sp <= sp + 1;

                                if (left_child[current_node] == 0) begin
                                    stack[sp] <= left_child[current_node];
                                    sp <= sp + 1;
                                    temp_data <= current_node;
                                    sorted_out[output_index] <= temp_data;
                                    output_index <= output_index + DATA_WIDTH;
                                    sp <= sp - 1;
                                    if (sp >= $clog2(ARRAY_SIZE)) begin
                                        stack <= stack[0:sp];
                                        sp <= 0;
                                    end
                                    continue;
                                end

                                if (right_child[current_node] == 0) begin
                                    stack[sp] <= right_child[current_node];
                                    sp <= sp + 1;
                                    temp_data <= current_node;
                                    sorted_out[output_index] <= temp_data;
                                    output_index <= output_index + DATA_WIDTH;
                                    sp <= sp - 1;
                                    if (sp >= $clog2(ARRAY_SIZE)) begin
                                        stack <= stack[0:sp];
                                        sp <= 0;
                                    end
                                    continue;
                                end

                                temp_data <= current_node;
                                sorted_out[output_index] <= temp_data;
                                output_index <= output_index + DATA_WIDTH;
                                sp <= sp - 1;
                                if (sp >= $clog2(ARRAY_SIZE)) begin
                                    stack <= stack[0:sp];
                                    sp <= 0;
                                end
                            end

                            done <= 1;
                            top_state <= IDLE;
                        end
                end
            endcase
        end
    end
endmodule

output.rtl/search_binary_search_tree.sv:
module search_binary_search_tree #(
    parameter DATA_WIDTH = 32,
    parameter ARRAY_SIZE = 15
) (
    input clk,
    input reset,
    input reg start,
    input reg [DATA_WIDTH-1:0] search_key,
    input reg [$clog2(ARRAY_SIZE):0] root,
    input reg [ARRAY_SIZE*DATA_WIDTH-1:0] keys,
    input reg [ARRAY_SIZE*($clog2(ARRAY_SIZE)+1)-1:0] left_child,
    input reg [ARRAY_SIZE*($clog2(ARRAY_SIZE)+1)-1:0] right_child,
    output reg [$clog2(ARRAY_SIZE):0] key_position,
    output reg complete_found,
    output reg search_invalid
);

    // FSM states
    parameter S_IDLE = 3'b000,
              S_INIT = 3'b001,
              S_SEARCH_LEFT = 3'b010,
              S_SEARCH_LEFT_RIGHT = 3'b011,
              S_COMPLETE_SEARCH = 3'b100;

    // FSM state register
    reg [2:0] search_state;

    // Variables for traversal
    reg [$clog2(ARRAY_SIZE):0] position;
    reg found;

    // Stack for traversal
    reg [ARRAY_SIZE*($clog2(ARRAY_SIZE)+1)-1:0] left_stack;
    reg [ARRAY_SIZE*($clog2(ARRAY_SIZE)+1)-1:0] right_stack;
    reg [$clog2(ARRAY_SIZE):0] sp_left;
    reg [$clog2(ARRAY_SIZE):0] sp_right;

    // Pointers for current nodes
    reg [$clog2(ARRAY_SIZE):0] current_left_node;
    reg [$clog2(ARRAY_SIZE):0] current_right_node;

    // Output indices for traversal
    reg [$clog2(ARRAY_SIZE):0] left_output_index;
    reg [$clog2(ARRAY_SIZE):0] right_output_index;

    // Loop index
    integer i;

    // Always block
    always @(posedge clk or posedge reset) begin
        if (reset) begin
            // Reset all states and variables
            search_state <= S_IDLE;
            found <= 0;
            position <= {($clog2(ARRAY_SIZE)+1){1'b1}};
            complete_found <= 0;
            key_position <= {($clog2(ARRAY_SIZE)+1){1'b1}};
            left_output_index <= 0;
            right_output_index <= 0;
            sp_left <= 0;
            sp_right <= 0;
            current_left_node <= 0;
            current_right_node <= 0;
            left_done <= 0;
            right_done <= 0;
            search_state <= S_IDLE;
            search_invalid <= 0;
        end else begin
            if (start) begin
                search_state <= S_INIT;
                found <= 0;
                position <= {($clog2(ARRAY_SIZE)+1){1'b1}};
                key_position <= {($clog2(ARRAY_SIZE)+1){1'b1}};
                left_output_index <= 0;
                right_output_index <= 0;
                sp_left <= 0;
                sp_right <= 0;
                current_left_node <= 0;
                current_right_node <= 0;
                left_done <= 0;
                right_done <= 0;
            end
        end
    end

    // Case for initialization
    case (search_state)
        S_IDLE: begin
            for (i = 0; i < ARRAY_SIZE+1; i = i + 1) begin
                left_stack[i*($clog2(ARRAY_SIZE)+1) +: ($clog2(ARRAY_SIZE)+1)] <= {($clog2(ARRAY_SIZE)+1){1'b1}};
                right_stack[i*($clog2(ARRAY_SIZE)+1) +: ($clog2(ARRAY_SIZE)+1)] <= {($clog2(ARRAY_SIZE)+1){1'b1}};
            end
            complete_found <= 0;
            search_invalid <= 0;

            if (start) begin
                search_state <= S_INIT;
                found <= 0;
                position <= {($clog2(ARRAY_SIZE)+1){1'b1}};
                key_position <= {($clog2(ARRAY_SIZE)+1){1'b1}};
                left_output_index <= 0;
                right_output_index <= 0;
                sp_left <= 0;
                sp_right <= 0;
                current_left_node <= 0;
                current_right_node <= 0;
                left_done <= 0;
                right_done <= 0;
            end
        end

        S_INIT: begin
            if (root == 0) begin
                search_invalid <= 1;
                key_position <= {($clog2(ARRAY_SIZE)+1){1'b1}};
                complete_found <= 0;
                search_state <= S_IDLE;
                continue;
            end
            if (search_key < root) begin
                search_state <= S_SEARCH_LEFT;
            elsif (search_key > root) begin
                search_state <= S_SEARCH_LEFT_RIGHT;
            else begin
                found <= 1;
                key_position <= root;
                complete_found <= 1;
                search_state <= S_COMPLETE_SEARCH;
            end
        end

        S_SEARCH_LEFT: begin
            if (left_stack[sp_left*($clog2(ARRAY_SIZE)+1) + left_output_index] == 1) begin
                left_output_index <= left_output_index + 1;
                current_left_node <= left_stack[sp_left*($clog2(ARRAY_SIZE)+1) + left_output_index];
                sp_left <= sp_left + 1;

                if (left_child[current_left_node] == 1) begin
                    left_output_index <= left_output_index - 1;
                    left_done <= 1;
                    left_output_index <= left_output_index - 1;
                    current_left_node <= left_child[current_left_node];
                    sp_left <= left_output_index;
                end
            end
            search_state <= S_SEARCH_LEFT;
        end

        S_SEARCH_LEFT_RIGHT: begin
            if (left_stack[sp_left*($clog2(ARRAY_SIZE)+1) + left_output_index] == 1) begin
                left_output_index <= left_output_index + 1;
                current_left_node <= left_stack[sp_left*($clog2(ARRAY_SIZE)+1) + left_output_index];
                sp_left <= sp_left + 1;
            end
            if (right_stack[sp_right*($clog2(ARRAY_SIZE)+1) + right_output_index] == 1) begin
                right_output_index <= right_output_index + 1;
                current_right_node <= right_stack[sp_right*($clog2(ARRAY_SIZE)+1) + right_output_index];
                sp_right <= sp_right + 1;
            end
            search_state <= S_SEARCH_LEFT_RIGHT;
        end

        S_COMPLETE_SEARCH: begin
            if (found) begin
                complete_found <= 1;
                key_position <= key_position[sp_left*($clog2(ARRAY_SIZE)+1) + ($clog2(ARRAY_SIZE)+1)];
                search_state <= S_IDLE;
            end
            search_invalid <= 0;
            sp_left <= 0;
            sp_right <= 0;
            left_output_index <= 0;
            right_output_index <= 0;
            left_done <= 0;
            right_done <= 0;
        end

        default: begin
            search_state <= S_IDLE;
        end
    endcase
endmodule

