output.rtl/pseudo_lru_nmru_policy.sv:
module pseudo_lru_nmru_policy #(
    NWAYS = 4,
    NINDEXES = 32
) (
    input clock,
    input reset,
    input [$clog2(NINDEXES)-1:0] index,
    input [$clog2(NWAYS)-1:0] way_select,
    input access,
    input hit,
    output [$clog2(NWAYS)-1:0] way_replace
);

reg [NWAYS-1:0] recency [NINDEXES-1:0];
reg reset_counter;

integer reset_counter;
always_ff @ (posedge clock or posedge reset) begin
    if (reset) begin
        for (reset_counter = 0; reset_counter < NINDEXES; reset_counter = reset_counter + 1) begin
            recency[reset_counter] <= {NWAYS{1'b0}};
        end
    else begin

        if (hit) begin
            recency[index] <= 1;
        else begin
            // Find all ways with zero recency
            reg [NWAYS-1:0] zero_ways;
            for (int i = 0; i < NWAYS; i = i + 1) begin
                if (recency[i] == 0) begin
                    zero_ways <= i;
                end
            end

            // If only one zero way, use it
            if (zero_ways[0] != -1) begin
                way_replace <= zero_ways[0];
                recency[way_replace] <= 1;
                for (int i = 0; i < NWAYS; i = i + 1) begin
                    if (i != way_replace) begin
                        recency[i] <= 0;
                    end
                end
            // If multiple zeros, use smallest index
            else begin
                way_replace <= zero_ways;
                recency[way_replace] <= 1;
                for (int i = 0; i < NWAYS; i = i + 1) begin
                    if (i != way_replace) begin
                        recency[i] <= 0;
                    end
                end
            end
        end
    end
end

endmodule

output.rtl/mru_counter_policy.sv:
module mru_counter_policy #(
    parameter NWAYS = 4,
    parameter NINDEXES = 32
)(
    input clock,
    input reset,
    input [$clog2(NINDEXES)-1:0] index,
    input [$clog2(NWAYS)-1:0] way_select,
    input access,
    input hit,
    output [$clog2(NWAYS)-1:0] way_replace
);

    reg [(NWAYS * $clog2(NWAYS))-1:0] recency [NINDEXES-1:0];

    wire [$clog2(NWAYS)-1:0] mru_slot;

    always_ff @ (posedge clock or posedge reset) begin
        if (reset) begin
            for (i = 0; i < NINDEXES; i = i + 1) begin
                for (n = 0; n < NWAYS; n = n + 1) begin
                    recency[i][(n * $clog2(NWAYS)) +: $clog2(NWAYS)] <= $clog2(NWAYS)'(n);
                end
            end
        else begin
            if (access) begin
                // Hit case
                integer current_val;
                current_val = recency[index][way_select];
                recency[index][way_select] <= $clog2(NWAYS)-1;
                for (n = 0; n < NWAYS; n = n + 1) begin
                    if (n != way_select) begin
                        if (recency[index][n] > current_val) begin
                            recency[index][n] <= recency[index][n] - 1;
                        end
                    end
                end
            else begin
                // Miss case
                integer max_val = -1;
                integer mru_ways = -1;
                for (n = 0; n < NWAYS; n = n + 1) begin
                    if (recency[index][n] > max_val) begin
                        max_val = recency[index][n];
                        mru_ways = n;
                    end
                end
                recency[index][mru_ways] <= $clog2(NWAYS)-1;
                for (n = 0; n < NWAYS; n = n + 1) begin
                    if (n != mru_ways) begin
                        if (recency[index][n] > max_val) begin
                            recency[index][n] <= recency[index][n] - 1;
                        end
                    end
                end
            end
        end
    end

    assign way_replace = mru_ways;
endmodule

output.rtl/lfu_counter_policy.sv:
module lfu_counter_policy #(
    parameter NWAYS = 4,
    parameter NINDEXES = 32,
    parameter COUNTERW = 2
)(
    input clock,
    input reset,
    input [$clog2(NINDEXES)-1:0] index,
    input [$clog2(NWAYS)-1:0] way_select,
    input access,
    input hit,
    output [$clog2(NWAYS)-1:0] way_replace
);

    localparam int unsigned MAX_FREQUENCY = $pow(2, COUNTERW) - 1;

    // Frequency array to track next way to be replaced
    reg [(NWAYS * COUNTERW)-1:0] frequency [NINDEXES-1:0];

    integer i, n;

    // Sequential logic for reset and frequency updates
    always_ff @ (posedge clock or posedge reset) begin
        if (reset) begin
            for (i = 0; i < NINDEXES; i = i + 1) begin
                for (n = 0; n < NWAYS; n = n + 1) begin
                    frequency[i][(n * COUNTERW) +: COUNTERW] <= COUNTERW'(0);
                end
            end
        else begin
            if (access) begin
                // Hit case: Increment frequency for accessed way
                way_select n = way_select;
                if (frequency[index][way_select] < MAX_FREQUENCY) begin
                    frequency[index][way_select] <= frequency[index][way_select] + 1;
