            if (parked_time % 3600 > 0) begin
                calculate_fee = ((parked_time / 3600) + 1)*fee_per_hour; // Round up to the next hour if there's a remainder
            end else begin
                calculate_fee = ((parked_time / 3600))*fee_per_hour;
            end
        end
    endfunction

