module cascaded_adder(
    input clock,
    input rst_n,
    input i_valid,
    input [IN_DATA_WIDTH * IN_DATA_NS - 1:0] i_data,
    output [IN_DATA_WIDTH + log2(IN_DATA_NS) - 1:0] o_data,
    output o_valid
);
    // Reset handling
    always @ (rst_n) begin
        o_valid = 0;
        o_data = 0;
    end

    // Clock gating
    clock_gating o_validclk (rst_n, o_valid);

    // Data accumulation
    reg [IN_DATA_WIDTH * IN_DATA_NS - 1:0] acc_sum = 0;
    reg [IN_DATA_WIDTH * IN_DATA_NS - 1:0] current_data;

    // Process each data element
    always @ (i_valid) begin
        current_data = i_data;
        for (int i = 0; i < IN_DATA_NS; i++) begin
            acc_sum = (acc_sum << IN_DATA_WIDTH) + current_data;
            current_data = 0;
        end
    end

    // Output the accumulated sum
    o_valid = 1;
    o_data = acc_sum;
endmodule

module cascaded_adder #(
    parameter int IN_DATA_WIDTH = 16,
    parameter int IN_DATA_NS = 4,
    parameter int NUM_STAGES = $clog2(IN_DATA_NS),
    parameter logic [NUM_STAGES-1:0] REG = {NUM_STAGES{1'b1}}
) (
    input logic clk,
    input logic rst_n,
    input logic i_valid,
    input logic [IN_DATA_WIDTH*IN_DATA_NS-1:0] i_data,
    output logic o_valid,
    output logic [(IN_DATA_WIDTH+$clog2(IN_DATA_NS))-1:0] o_data
)
    // Internal signals for the adder tree
    logic [IN_DATA_WIDTH*IN_DATA_NS-1:0] i_data_ff;
    logic [IN_DATA_WIDTH-1:0] in_data_2d [IN_DATA_NS-1:0];
    logic [(IN_DATA_WIDTH+$clog2(IN_DATA_NS))-1:0] stage_output [NUM_STAGES-1:0][IN_DATA_NS>>1-1:0];
    logic valid_ff;
    logic valid_pipeline [NUM_STAGES-1:0];

    // Register the input data on valid signal
    always_ff @(posedge clk or negedge rst_n) begin : reg_indata
        if(!rst_n)
            i_data_ff <= 0;
        else begin
            if(i_valid) begin
                i_data_ff <= i_data;
            end
        end
    end

    // Convert flattened input to 2D array
    always_comb begin
        for (int i = 0; i < IN_DATA_NS; i++) begin : conv_1d_to_2d
            in_data_2d[i] = i_data_ff[(i+1)*IN_DATA_WIDTH-1:IN_DATA_WIDTH];
        end
    end

    // Parallel adder logic using generate statements
    generate
        for (int stage = 0; stage < NUM_STAGES; stage++) begin : adder_stage
            // Compute sums for current stage
            logic [IN_DATA_WIDTH-1:0] sum = in_data_2d[0:IN_DATA_NS-1:2] + in_data_2d[1:IN_DATA_NS-1:2];
            logic [IN_DATA_WIDTH-1:0] carry;

            if (sum & carry) begin
                sum = sum ^ carry;
                carry = (sum & carry) << 1;
            end else begin
                sum = sum + carry;
                carry = 0;
            end

            // Update stage_output based on REG bit
            if (REG[stage]) begin
                stage_output[stage] = sum + carry;
                carry = 0;
            else begin
                stage_output[stage] = sum;
            end
        end
    end

    always_ff @(posedge clk or negedge rst_n) begin
        if(!rst_n)
            valid_ff <= 1'b0;
        else 
            valid_ff <= i_valid;
    end

    // Valid signal propagation with latency based on REG
    always_ff @(posedge clk or negedge rst_n) begin
        if(!rst_n) begin
            o_valid <= 1'b0;
            for (int i = 0; i < NUM_STAGES; i++) begin
                valid_pipeline[i] <= valid_ff;
            end
        end else 
            valid_pipeline[NUM_STAGES-1] <= valid_ff;
    end

    // Assign the final stage of valid_pipeline to o_valid
    always_ff @(posedge clk or negedge rst_n) begin
        if(!rst_n)
            o_valid <= 1'b0;
        else
            o_valid <= valid_pipeline[NUM_STAGES-1];
    end

    // Output data assignment
    always_ff @(posedge clk or negedge rst_n) begin : reg_outdata
        if ( !rst_n) begin
            o_data <= 0 ;
        end else if (valid_pipeline[NUM_STAGES-1]) begin
            o_data <= stage_output[NUM_STAGES-1][0];
        end
    end
endmodule

