                // SHIFT left by 2 bits
                shift_reg_d[SHIFT_W-1:2] = shift_reg_q[SHIFT_W-3:0];
                shift_reg_d[1:0]         = 2'b00;
                count_d                  = count_q + 2;
              end
              else begin
                // Normal MSB-first => shift left by 1
                shift_reg_d = {shift_reg_q[SHIFT_W-2:0], 1'b0};
                count_d     = count_q + 1;
              end
            end
            else begin
              // LSB-first => shift right by 1 (no bug)
              shift_reg_d = {1'b0, shift_reg_q[SHIFT_W-1:1]};
              count_d     = count_q + 1;
            end
          end
        end
      end

      default: begin
        state_d = ST_RX; // safe fallback
      end
    endcase
  end

  // Outputs
  assign s_valid_o = (state_q == ST_TX);

  // LSB-first => s_data_o = shift_reg_q[0]
  // MSB-first => s_data_o = shift_reg_q[SHIFT_W-1]
  assign s_data_o  = (BIT_ORDER == 0) ? shift_reg_q[0] : shift_reg_q[SHIFT_W-1];

  assign p_ready_o = (state_q == ST_RX);

endmodule

output.rtl/data_width_converter.sv:
module data_width_converter(
    input clock,
    input reset,
    input data_in,
    input data_valid,
    output o_data_out,
    output o_data_out_valid
);

    // State variable to track the phase of the conversion process
    reg state = idle;

    // Internal buffer to store up to four 32-bit data chunks
    reg [32] data_buffer[4];

    // Internal counter to track the number of valid data chunks
    reg count = 0;

    // Process the data on positive edge of clock
    always clock positive edge begin
        if (reset) begin
            // Reset all internal states and outputs
            state = idle;
            o_data_out = 0;
            o_data_out_valid = 0;
            data_buffer[0:3] = 0;
            count = 0;
        else begin
            if (data_valid) begin
                // Store the valid data chunk
                data_buffer[count] = data_in;
                count = count + 1;

                // If we've collected four valid chunks, concatenate them
                if (count == 4) begin
                    // Concatenate the four 32-bit chunks into a 128-bit output
                    o_data_out = data_buffer[3] |
                        (data_buffer[2] << 32) |
                        (data_buffer[1] << 64) |
                        (data_buffer[0] << 96);
                    o_data_out_valid = 1;
                    // Reset the buffer and counter after output
                    data_buffer[0:3] = 0;
                    count = 0;
                end
            end
        end
    end

    // Indicate that no data is available until four valid chunks are received
    always begin
        if (!reset && !o_data_out_valid) begin
            o_data_out = 0;
        end
    end
endmodule

output.rtl/dbi_enc.sv:
module dbi_enc(
    input wire [39:0] data_in,
    input clock,
    input rst_n,
    output wire [39:0] data_out,
    output [1:0] dbi_cntrl
);
    reg [39:0] prev_data1, prev_data0;
    reg [1:0] cnt1, cnt0;

    always @edge clock begin
        if (rst_n) begin
            prev_data1 = 0;
            prev_data0 = 0;
            data_out = 0;
            dbi_cntrl = 0b00;
            cnt1 = 0;
            cnt0 = 0;
            return;
        end

        // Split data into groups
        reg group1, group0;
        group1 = data_in[39:20];
        group0 = data_in[19:0];

        // Compare with previous data
        cnt1 = 0;
        for (int i = 0; i < 20; i++) {
            if ((group1 >> i & 1) != (prev_data1 >> i & 1)) cnt1++;
        }
        cnt0 = 0;
        for (int i = 0; i < 20; i++) {
            if ((group0 >> i & 1) != (prev_data0 >> i & 1)) cnt0++;
        }

        // Determine control bits
        dbi_cntrl[1] = cnt1 > 10;
        dbi_cntrl[0] = cnt0 > 10;

        // Update previous data
        prev_data1 = group1;
        prev_data0 = group0;

        // Generate output
        if (dbi_cntrl[1]) {
            data_out[39:20] = ~group1;
        } else if (dbi_cntrl[0]) {
            data_out[19:0] = ~group0;
        } else {
            data_out = data_in;
        }
    end
endmodule

output.rtl/dbi_dec.sv:
module dbi_dec (
   input wire rst_n,
   input wire clk,
   input wire [39:0] data_in,
   input wire [1:0] dbi_cntrl,
   output wire [39:0] data_out
);

   reg group1, group0;

   if (rst_n) begin
      group1 = 0;
      group0 = 0;
   else begin
      group1 = (data_in[39:20]);
      group0 = (data_in[19:0]);

      if (dbi_cntrl[0]) begin
         group1 = group1 ^ 0x00FFFFFF;
         group0 = group0 ^ 0x00FFFFFF;
      end

      data_out = (group1 << 20) | group0;
   end

endmodule

