module ping_pong_fifo_2_axi_stream #( 
    parameter DATA_WIDTH = 32
)(
    input  logic                                 rst,
    input  logic                                 i_flush,
    input  logic                                 i_pause,
    input  logic                                 i_block_fifo_rdy,
    output logic                                 o_block_fifo_act,
    output logic                                 o_block_fifo_stb,
    input  logic [23:0]                          i_block_fifo_size,
    input  logic [(DATA_WIDTH + 1) - 1:0]        i_block_fifo_data,
    output logic                                 o_block_fifo_stb,
    input  logic                                 i_axi_user,
    input  logic                                 i_axi_clk,
    output logic [3:0]                           o_axi_user,
    input  logic                                 i_axi_ready,
    output logic [DATA_WIDTH - 1:0]              o_axi_data,
    output logic                                 o_axi_last,
    output logic                                 o_axi_valid
);

    // Internal Registers
    logic [23:0] block_size_reg;
    logic [23:0] data_count;
    logic        fifo_active;
    logic        data_valid;
    logic        data_pending;
    logic        fifo_data_valid;
    logic        fifo_data_reg [DATA_WIDTH - 1:0];

    logic state_t;
    state_t current_state, next_state;

    // State Definitions
    enum logic state_t {
        IDLE,
        READ_FIFO,
        SEND_AXI
    };

    always_ff @(posedge i_axi_clk or posedge rst) begin
        if (rst) begin
            current_state      <= IDLE;
            block_size_reg     <= 24'd0;
            data_count         <= 24'd0;
            fifo_active        <= 1'b0;
            data_pending       <= 1'b0;
            fifo_data_valid     <= 1'b0;
            fifo_data_reg       <= {DATA_WIDTH{1'b0}};
            o_block_fifo_act   <= 1'b0;
            o_block_fifo_stb   <= 1'b0;
            o_axi_valid        <= 1'b0;
            o_axi_data         <= {DATA_WIDTH{1'b0}};
            o_axi_last         <= 1'b0;
            o_axi_user         <= 4'd0;
        end else begin
            current_state      <= next_state;
            o_block_fifo_act   <= 1'b0;
            o_block_fifo_stb   <= 1'b0;
            o_axi_valid        <= 1'b0;
            o_axi_last         <= 1'b0;
            o_axi_user         <= 4'd0;

            case (current_state)
                IDLE: begin
                    if (i_block_fifo_rdy) begin
                        o_block_fifo_act <= 1'b1; 
                        block_size_reg    <= i_block_fifo_size;
                        fifo_active       <= 1'b1;
                        data_count        <= 24'd0;
                        next_state        <= READ_FIFO;
                    end else begin
                        next_state <= IDLE;
                    end
                end

                READ_FIFO: begin
                    if (fifo_active && i_block_fifo_rdy) begin
                        o_block_fifo_stb <= 1'b1; 
                        data_count       <= data_count + 24'd1;
                        data_pending      <= 1'b1;
                        next_state       <= SEND_AXI;
                    end else begin
                        next_state <= READ_FIFO;
                    end
                end

                SEND_AXI: begin
                    if (fifo_active && i_axi_ready) begin
                        o_axi_valid  <= 1'b1;
                        o_axi_data   <= fifo_data_reg;
                        o_axi_user   <= i_axi_user;

                        if (data_count + 24'd1 >= block_size_reg) begin
                            o_axi_last <= 1'b1;
                            fifo_active <= 1'b0;
                            next_state  <= IDLE;
                        end else begin
                            next_state <= SEND_AXI;
                        end
                    end else begin
                        next_state <= SEND_AXI;
                    end
                end

                default: next_state <= IDLE;
            endcase
        end
    end

    // Flush Control
    always_ff @(i_flush or i_pause or posedge i_axi_clk) begin
        if (i_flush) begin
            current_state <= IDLE;
            block_size_reg <= 24'd0;
            data_count    <= 24'd0;
            fifo_active   <= 1'b0;
            data_pending   <= 1'b0;
            fifo_data_valid <= 1'b0;
            fifo_data_reg  <= {DATA_WIDTH{1'b0}};
            o_block_fifo_act <= 1'b0;
            o_block_fifo_stb <= 1'b0;
            o_axi_valid    <= 1'b0;
            o_axi_data     <= {DATA_WIDTH{1'b0}};
            o_axi_last     <= 1'b0;
            o_axi_user     <= 4'd0;
        end
    end

    // Pause Control
    always_ff @(i_pause or posedge i_axi_clk) begin
        if (i_pause && current_state == SEND_AXI) begin
            o_axi_valid <= 1'b0;
            o_axi_data  <= {DATA_WIDTH{1'b0}};
            o_axi_user  <= 4'd0;
        end
    end
endmodule

output.rtl/FILO_RTL.sv:
module FILO_RTL (
    input clock,
    input reset,
    input push,
    input pop,
    input data_in,
    output data_out,
    output full,
    output empty
);

    parameter DATA_WIDTH = 8;
    parameter FILO_DEPTH = 16;

    reg top = 0;
    reg full = 0;
    reg empty = 1;

    always clock positive edge #100 begin
        if (reset) begin
            top = 0;
            empty = 1;
            full = 0;
        end else if (push) begin
            if (top < FILO_DEPTH) begin
                top++;
                full = (top == FILO_DEPTH);
                empty = ~empty;
            end
        end else if (pop) begin
            if (top > 0) begin
                top--;
                empty = (top == 0);
                full = ~full;
            end
        end else if (push & pop) begin
            data_out = data_in;
        end
    end
endmodule

input.rtl/FILO_RTL.sv:
module FILO_RTL #(
    parameter DATA_WIDTH = 8,  // Width of the data entries
    parameter FILO_DEPTH = 16  // Depth of the FILO buffer
) (
    input  wire                  clk,       // Clock signal
    input  wire                  reset,     // Asynchronous reset signal
    input  wire                  push,      // Push control signal
    input  wire                  pop,       // Pop control signal
    input  wire [DATA_WIDTH-1:0] data_in,   // Data input
    output reg  [DATA_WIDTH-1:0] data_out,  // Data output
    output reg                   full,      // Full status signal
    output reg                   empty      // Empty status signal
);


  reg [DATA_WIDTH-1:0] memory[FILO_DEPTH-1:0];  
  reg [$clog2(FILO_DEPTH):0] top;  

  reg feedthrough_valid;
  reg [DATA_WIDTH-1:0] feedthrough_data;


  always @(posedge clk or posedge reset) begin
    if (reset) begin
      top <= 0;
      empty <= 1;
      full <= 0;
      feedthrough_valid <= 0;
      data_out <= 0;  
    end else begin

      if (push && pop && empty) begin
        data_out <= data_in; 
        feedthrough_data <= data_in;
        feedthrough_valid <= 1;
      end else begin

        if (push && !full) begin
          memory[top] <= data_in;  
          top <= top + 1;  
          feedthrough_valid <= 0;
        end

        if (pop && !empty) begin
          if (feedthrough_valid) begin
            data_out <= feedthrough_data;  
            feedthrough_valid <= 0;
          end else begin
            top <= top; 
            data_out <= memory[top-1]; 
          end
        end
      end

      empty <= (top == 0);
      full  <= (top == FILO_DEPTH);  
    end
  end
endmodule

