module divider #(parameter WIDTH = 32)
(
    parameter WIDTH = 32
)
(
    input  wire                  clk,
    input  wire                  rst_n,
    input  wire                  start,
    input  wire [WIDTH-1 : 0]    dividend,
    input  wire [WIDTH-1 : 0]    divisor,
    output wire [WIDTH-1 : 0]    quotient,
    output wire [WIDTH-1 : 0]    remainder,
    output wire                  valid
);

    // one extra bit for A
    localparam AW = WIDTH + 1;
    // Simple 3-state FSM
    localparam IDLE = 2'b00;
    localparam BUSY = 2'b01;
    localparam DONE = 2'b10;

    reg [1:0] state_reg, state_next;

    // A+Q combined into one WIDTH + 1 + WIDTH register:
    reg [AW+WIDTH-1 : 0] aq_reg,   aq_next;

    // Divisor register
    reg [AW-1 : 0]       m_reg,    m_next;

    // Iterate exactly WIDTH times
    reg [$clog2(WIDTH)-1:0] n_reg, n_next;

    // Final outputs
    reg [WIDTH-1:0] quotient_reg, quotient_next;
    reg [WIDTH-1:0] remainder_reg, remainder_next;
    reg valid_reg, valid_next;

    // Assign the top-level outputs
    assign quotient  = quotient_reg;
    assign remainder = remainder_reg;
    assign valid     = valid_reg;

    //------------------------------------------------
    // SEQUENTIAL: State & register updates
    //------------------------------------------------
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            state_reg     <= IDLE;
            aq_reg        <= 0;
            m_reg         <= 0;
            n_reg         <= 0;
            quotient_reg  <= 0;
            remainder_reg <= 0;
            valid_reg     <= 0;
        else begin
            state_reg     <= state_next;
            aq_reg        <= aq_next;
            m_reg         <= m_next;
            m_next         = 0;
            n_reg         <= n_next;
            n_next         = n_reg - 1;
            quotient_reg  <= quotient_next;
            remainder_reg <= remainder_next;
            valid_reg     <= valid_next;
        end
    end

    //------------------------------------------------
    // COMBINATIONAL: Next-state logic
    //------------------------------------------------
    always @* begin
        state_next     = state_reg;
        aq_next_tmp    = aq_reg << 1;
        aq_next_tmp[AW+WIDTH-1 : WIDTH] = aq_next_tmp[AW+WIDTH-1 : WIDTH] + m_reg;
        aq_next_tmp[AW+WIDTH-1 : WIDTH] = aq_next_tmp[AW+WIDTH-1 : WIDTH] - m_reg;
        if (aq_next_tmp[AW+WIDTH-1] == 1'b1) begin
            aq_next_tmp[0] = 1'b0;
        end else begin
            aq_next_tmp[0] = 1'b1;
        end

        state_next     = BUSY;
        n_next         = n_reg - 1;
        quotient_next  = quotient_reg;
        remainder_next = remainder_reg;
        valid_next     = valid_reg;
    end

    //------------------------------------------------
    // DONE: Final correction + output
    //------------------------------------------------
    DONE: begin
        if (aq_reg[AW+WIDTH-1] == 1'b1) begin
            aq_next_tmp = aq_reg;
            aq_next_tmp[AW+WIDTH-1 : WIDTH] = aq_next_tmp[AW+WIDTH-1 : WIDTH] + m_reg;
        end

        quotient_next  = aq_next_tmp[WIDTH-1 : 0];
        remainder_next = aq_next_tmp[2*WIDTH-1 : WIDTH];
        valid_next     = 1'b1;

        if (!start) begin
            state_next = IDLE;
        else begin
            state_next = DONE;
        end
    end

    default: begin
        state_next = IDLE;
    end
endmodule

