module gf_mac (
    parameter WIDTH,
    input [WIDTH-1:0] a,
    input [WIDTH-1:0] b,
    output [7:0] result
);

    integer i, N;

    N = WIDTH / 8;
    result = 0;

    for (i = 0; i < N; i = i + 1) begin
        a_segment = a[i*8 +7: i*8];
        b_segment = b[i*8 +7: i*8];
        result = result ^ gf_multiplier(a_segment, b_segment);
    end

    // Polynomial reduction if overflow occurs
    // The irreducible_poly is defined in gf_multiplier
endmodule

