module gmii_rx_to_axi_stream (
    input wire        gmii_rx_clk,
    input wire [7:0]  gmii_rxd,
    input wire        gmii_rx_dv,
    output wire [7:0] m_axis_tdata,
    output wire       m_axis_tvalid,
    input wire        m_axis_tready,
    output wire       m_axis_tlast
);

    localparam IDLE = 2'b00,
               RECEIVING = 2'b01,
               FINISHED = 2'b10;

    reg    state = IDLE,
           cnt    = 0,
           buffer [7:0] = 0;

    always @ (gmii_rx_clk) begin
        if (gmii_rx_dv) begin
            state = RECEIVING;
        end else begin
            if (state == IDLE) state = IDLE;
        end

        if (state == RECEIVING) begin
            cnt = cnt + 1;
            buffer = buffer + (gmii_rxd[7:0]);
            if (cnt == 8) begin
                m_axis_tvalid = 1;
                m_axis_tlast  = 1;
                state = FINISHED;
            end else begin
                m_axis_tvalid = 0;
            end
        end else begin
            m_axis_tvalid = 0;
        end
    end

    // Wait for tready before asserting tvalid
    while (m_axis_tready == 0) m_axis_tvalid = 0;

endmodule

