     end
   end

   always_comb begin
     if (clr_en) begin
       w1_reg = 0;
       w2_reg = 0;
       bias_reg = 0;
     end else begin
       w1_reg = w1_reg + 4'h0;
       w2_reg = w2_reg + 4'h0;
       bias_reg = bias_reg + 4'h0;
     end
   end

   always_comb begin
     case(present_state)
             S0  : begin
                clr_en = 1;
                cap_en = 0;
                delta_en = 0;
                sum_en   = 0;
                iteration = 0;
                target = target + 4'h0;
              end
             S1  : begin
                clr_en = 0;
                cap_en = 1;
                delta_en = 0;
                sum_en = 0;
                iteration = iteration + 0;
                target = target + 4'h0;
              end
             S2  : begin
                clr_en = 0;
                cap_en = 0;
                delta_en = 0;
                sum_en = 0;
                iteration = iteration + 0;
                target = target + 4'h0;
              end
             S3  : begin
                clr_en = 0;
                cap_en = 0;
                delta_en = 0;
                sum_en = 0;
                iteration = iteration + 0;
                target = target + 4'h0;
              end
             S4  : begin
                clr_en = 0;
                cap_en = 0;
                delta_en = 0;
                sum_en = 0;
                iteration = iteration + 0;
                target = target + 4'h0;
              end
             default : begin
                      clr_en = 0;
                      cap_en = 0;
                      delta_en = 0;
                      sum_en = 0;
                      iteration = 0;
                      target = target + 4'h0;
                     end
        endcase
   end

   // Testing FSM
   module test_fsm(
       input  clock,
       input  rst,
       input  gate_select,
       output logic [3:0] present_state,
       output logic [3:0] next_state,
       output logic [3:0] test_present_state,
       output logic [3:0] test_output,
       output logic [3:0] test_result,
       output logic [1:0] test_done
   )
      state (
          TEST_INITIAL,
          TESTFETCH,
          TESTCALC,
          TESTVERIFY,
          TEST_DONE
      );

      always_comb begin
        case (present_state)
          TEST_INITIAL : begin
            test_index = 4'b0000;
            test FSM is started after training completes
          end
          TESTFETCH : begin
            // Fetch test vectors
            case (test_index)
              4'b0000 : begin
                t1 = test_inputs_x1[0];
                t2 = test_inputs_x2[0];
                t3 = test_expected_outputs[0];
                test_index = 4'b0001;
              end
              4'b0001 : begin
                t1 = test_inputs_x1[1];
                t2 = test_inputs_x2[1];
                t3 = test_expected_outputs[1];
                test_index = 4'b0010;
              end
              // ... add all test cases ...
              4'b1111 : begin
                t1 = test_inputs_x1[15];
                t2 = test_inputs_x2[15];
                t3 = test_expected_outputs[15];
                test_index = 4'b0000;
              end
            endcase
          TESTCALC : begin
            // Perform calculation
            test_calc = (w1 * t1) + (w2 * t2) + bias;
            test_output = 4'd1 if test_calc > 0 else 4'd1;
          end
          TESTVERIFY : begin
            // Compare results
            if (test_output == t3) begin
              test_result = test_result + 4'h1;
            end
          end
          TEST_DONE : begin
            // Check if all tests passed
            if (test_index >= 4'b1000) begin
              test_done = 1;
            end
          end
        endcase
      end
   endmodule

module hebbian_rule (
    input wire [INPUT_WIDTH-1:0] a,
    input wire [INPUT_WIDTH-1:0] b,
    input wire gate_select,
    input wire clk,
    input wire rst,
    output register signed [INPUT_WIDTH-1:0] w1,
    output register signed [INPUT_WIDTH-1:0] w2,
    output register signed [INPUT_WIDTH-1:0] bias,
    output register [2*INPUT_WIDTH-1:0] present_state,
    output register [2*INPUT_WIDTH-1:0] next_state
);

    // FSM state variable
    reg state = 0;

    // State 0: Reset state
    always @posedge rst) 
        state = 0;

    // State 1: Capture inputs
    always @negedge rst) 
        if (start) begin
            state = 1;
            present_state <= 0;
            next_state <= 1;
        end

    // State 2: Assign target based on gate select
    always @negedge rst) 
        if (start && state == 2) begin
            case (gate_select)
                2'b00: target = a & b;
                2'b01: target = a | b;
                2'b10: target = ~a & ~b;
                2'b11: target = ~a | ~b;
            endcase
            state = 3;
            present_state <= 2;
            next_state <= 3;
        end

    // State 3: Compute deltas
    always @negedge rst) 
        if (start && state == 3) begin
            x1 = a;
            x2 = b;
            delta_w1 = x1 & target;
            delta_w2 = x2 & target;
            delta_b = target;
            state = 4;
            present_state <= 3;
            next_state <= 4;
        end

    // State 4: Update weights and bias
    always @negedge rst) 
        if (start && state == 4) begin
            w1 = w1 + delta_w1;
            w2 = w2 + delta_w2;
            bias = bias + delta_b;
            state = 5;
            present_state <= 4;
            next_state <= 5;
        end

    // State 5: Loop through training iterations
    always @negedge rst) 
        if (start && state == 5) begin
            state = 6;
            present_state <= 5;
            next_state <= 6;
        end

    // State 6: Return to initial state
    always @negedge rst) 
        if (start && state == 6) begin
            state = 0;
            present_state <= 6;
            next_state <= 0;
        end

endmodule

