module ir_receiver (
    input  logic        reset_in,       // Active HIGH reset
    input  logic        clk_in,         // System clock (100 KHz, 10us)
    input  logic        ir_signal_in,   // Input signal (IR)
    output logic [11:0] ir_frame_out,   // Decoded 12-bit frame
    output logic        ir_frame_valid  // Indicates validity of the decoded frame
);

    typedef enum logic [1:0] {idle, start, decoding, finish} ir_state;
    ir_state present_state, next_state;

    logic started; 
    logic decoded; 
    logic failed; 
    logic success;

    int cycle_counter; 
    int bit_counter;          

    logic [11:0] ir_frame_reg; 
    logic stored;                       

    always_ff @(posedge clk_in or posedge reset_in) begin
        if (reset_in)
            present_state <= idle;
        else
            present_state <= next_state;
    end

    always_comb begin
        case (present_state)
            idle: begin
                // Start bit detection
                if (!reset_in) begin
                    if (!ir_signal_in && present_state == idle) begin
                        present_state = start;
                    end
                end
            end
            start: begin
                // Data bit detection
                if (!reset_in) begin
                    bit_counter = 0;
                    ir_frame_reg = 0;
                    present_state = decoding;
                end
            end
            decoding: begin
                if (!reset_in && bit_counter < 12) begin
                    // Process data bit
                    if (ir_signal_in) begin
                        ir_frame_reg[bit_counter] = 1;
                    end else begin
                        ir_frame_reg[bit_counter] = 0;
                    end
                    bit_counter++;
                    present_state = decoding;
                end
            end
            finish: begin
                // Finalize output
                if (!reset_in) begin
                    ir_frame_valid = 1;
                    present_state = finish;
                end
            end
        end
    end

    // Edge case handling
    always @(posedge clk_in) begin
        if (!reset_in && present_state == idle) begin
            if (ir_signal_in && present_state == idle) begin
                present_state = start;
            end else begin
                present_state = idle;
            end
        end
        if (!reset_in && present_state == start) begin
            if (!ir_signal_in) begin
                present_state = idle;
            end
        end
        if (!reset_in && present_state == decoding) begin
            if (bit_counter != 12) begin
                present_state = decoding;
            end else begin
                present_state = finish;
            end
        end
    end
endmodule

module ir_receiver (
    input  logic        reset_in,               // Active HIGH reset
    input  logic        clk_in,                 // System clock (10 KHz, 100us)
    input  logic        ir_signal_in,           // Input signal (IR)
    output logic [6:0]  ir_function_code_out,   // Decoded output for different functions
    output logic [4:0]  ir_device_address_out,  // "00001": TV, "00010":HDMI1, "00100":USB, "01000":HDMI2, "10000": VCR
    output logic        ir_output_valid         // Indicates validity of the decoded frame
);

    typedef enum logic [2:0] {idle, start, decoding, finish, frame_space} ir_state;
    ir_state present_state, next_state;

    logic started;
    logic decoded;
    logic failed;
    logic success;
    logic frame_full;
    logic ir_frame_valid;

    int cycle_counter;
    int frame_space_counter;
    int bit_counter;

    logic [11:0] ir_frame_reg;
    logic [11:0] ir_frame_out;
    logic stored;

    always_ff @(posedge clk_in or posedge reset_in) begin
        if (reset_in)
            present_state <= idle;
        else
            present_state <= next_state;
    end

    always_comb begin
        case (present_state)
            idle: begin
                if (ir_signal_in == 1 && started == 0)
                    next_state = start;
                else
                    next_state = idle;
            end
            start: begin
                if (ir_signal_in == 0 && started == 1)
                    next_state = decoding;
                else if (failed == 1)
                    next_state = idle;
                else
                    next_state = start;
            end
            decoding: begin
                if (decoded == 1)
                    next_state = finish;
                else if (failed == 1)
                    next_state = idle;
                else
                    next_state = decoding;
            end
            finish: begin
                if (success == 1)
                    next_state = frame_space;
                else
                    next_state = finish;
                // Extract function code and device address
                ir_function_code_out = ir_frame_out[6:0];
                ir_device_address_out = ir_frame_out[4:0];
                ir_output_valid = 1;
                // Wait for frame space
                frame_space_counter = 0;
                while (frame_space_counter <= 44) #1 (45ms)
                    frame_space_counter++;
                next_state = idle;
            end

            // Insert code for decoding and frame space logic here
            ir_frame_reg = 0;
            frame_full = 0;
            ir_frame_valid = 0;
            bit_counter = 0;
        end
    end

    // Decoding logic
    decoding: begin
        if (ir_frame_valid) begin
            ir_frame_reg = 0;
            frame_full = 0;
            bit_counter = 0;
        end
        if (bit_counter < 12) begin
            if (ir_signal_in == 1 && bit_counter % 2 == 0) begin // 0.6ms LOW followed by HIGH
                ir_frame_reg = ir_frame_reg ^ (1 << (11 - bit_counter));
            end
            bit_counter = bit_counter + 1;
        end
        next_state = decoding;
    end
endmodule

