module load_store_unit(
    input clock,
    input rst_n,
    input [31:0] dmem_req_o,
    input [31:0] dmem_gnt_i,
    input [31:0] dmem_req_addr_o,
    input [3:0] dmem_req_be_o,
    input [31:0] dmem_req_wdata_o,
    input [1] ex_if_req_i,
    input [1] ex_if_we_i,
    input [2:0] ex_if_type_i,
    input [31:0] ex_if_addr_base_i,
    input [31:0] ex_if_addr_offset_i,
    output [1] ex_if_ready_o,
    output [32:0] wb_if_rdata_o,
    output [1] wb_if_rvalid_o
);

    // State variables
    reg ex_if_state = 0;
    reg mem_req_valid = 0;

    // Address calculation
    wire [31:0] dmem_req_addr = ex_if_addr_base_i + ex_if_addr_offset_i;

    // Byte enable mask generation
    function [4:0] byte_enable_mask;
        if (ex_if_type_i == 0b00) return 0b0000;
        if (ex_if_type_i == 0b01) return (ex_if_addr_offset_i & 0b00) ? 0b0011 : 0b1100;
        if (ex_if_type_i == 0b10) return 0b1111;
        return 0;
    endfunction

    // Memory interface
    wire [31:0] dmem_req_wdata = ex_if_addr_base_i + ex_if_addr_offset_i;
    wire [31:0] dmem_gnt = 0;
    wire [32:0] dmem_rvalid = 0;
    wire [32:0] dmem_rsp_rdata = 0;

    // Processing logic
    always clocked begin
        if (rst_n) begin
            ex_if_state = 0;
            mem_req_valid = 0;
            dmem_req_o = 0;
            dmem_req_addr_o = 0;
            dmem_req_we_o = 0;
            dmem_req_be_o = 0;
            dmem_req_wdata_o = 0;
            dmem_gnt_i = 0;
            dmem_rvalid_i = 0;
            wb_if_rdata_o = 0;
            wb_if_rvalid_o = 0;
        else begin
            if (ex_if_state == 0) begin
                if (ex_if_ready_o && ex_if_req_i && (dmem_gnt_i == 1)) begin
                    ex_if_state = 1;
                    dmem_req_o = 1;
                    dmem_req_addr_o = dmem_req_addr;
                    dmem_req_we_o = ex_if_we_i;
                    dmem_req_be_o = byte_enable_mask(ex_if_type_i);
                    dmem_req_wdata_o = 0;
                end
            end else if (ex_if_state == 1) begin
                if (dmem_gnt_i && dmem_rvalid_i) begin
                    ex_if_state = 2;
                    dmem_gnt_i = 0;
                    dmem_rvalid_i = 0;
                    dmem_rsp_rdata_i = 0;
                end
            end else if (ex_if_state == 2) begin
                if (dmem_gnt_i && dmem_rvalid_i) begin
                    ex_if_state = 0;
                    dmem_gnt_i = 0;
                    dmem_rvalid_i = 0;
                    dmem_rsp_rdata_i = 0;
                    if (ex_if_we_i) begin
                        wb_if_rvalid_o = 1;
                        wb_if_rdata_o = dmem_rsp_rdata_i;
                    end
                end
            end
        end
    end

    // Always block for memory operations
    always clocked begin
        if (ex_if_state == 1) begin
            // Send request to memory
            dmem_req_o = 1;
            dmem_req_addr_o = dmem_req_addr;
            dmem_req_we_o = ex_if_we_i;
            dmem_req_be_o = byte_enable_mask(ex_if_type_i);
            dmem_req_wdata_o = 0;
        end else if (ex_if_state == 2) begin
            // Memory has responded
            dmem_gnt_i = 0;
            dmem_rvalid_i = 1;
        end
    end
endmodule

input.rtl/load_store_unit.sv:
module load_store_unit (
    input  logic                 clk,
    input  logic                 rst_n,

    // EX stage interface
    input  logic                 ex_if_req_i,           // LSU request
    input  logic                 ex_if_we_i,            // Write enable: 0 (load), 1 (store)
    input  logic     [ 1:0]      ex_if_type_i,          // Data type: 0x2 (word), 0x1 (halfword), 0x0 (byte)
    input  logic     [31:0]      ex_if_wdata_i,         // Data to write to memory
    input  logic     [31:0]      ex_if_addr_base_i,     // Base address
    input  logic     [31:0]      ex_if_addr_offset_i,   // Offset address
    output logic                 ex_if_ready_o    ,

    // Writeback stage interface
    output logic     [31:0]      wb_if_rdata_o,         // Requested data
    output logic                 wb_if_rvalid_o,        // Requested data valid

    // Data memory (DMEM) interface
    output logic                 dmem_req_o,
    input  logic                 dmem_gnt_i,
    output logic     [31:0]      dmem_req_addr_o,
    output logic                 dmem_req_we_o,
    output logic     [ 3:0]      dmem_req_be_o,
    output logic     [31:0]      dmem_req_wdata_o,
    input  logic     [31:0]      dmem_rsp_rdata_i,
    input  logic                 dmem_rvalid_i
    );

  // Internal signals
  logic ex_req_fire;
  logic dmem_req_we_q;
  logic [31:0] data_addr_int;
  logic misaligned_addr;
  logic [3:0] dmem_be, dmem_req_be_q;

  logic busy_q;  // Sticky busy bit: Set with EX req and cleared with DMEM response
  logic dmem_req_q ;




  logic [31:0] dmem_req_wdata_q;
  logic [31:0] dmem_req_addr_q;

  logic [31:0] wb_if_rdata_q;
  logic wb_if_rvalid_q;

  // Address calculation
  assign data_addr_int = ex_if_addr_base_i + ex_if_addr_offset_i;

  // EX request fire condition
  assign ex_req_fire = ex_if_req_i && !busy_q && !misaligned_addr;
  assign ex_if_ready_o = !busy_q;

  ///////////////////////////////// Byte Enable Generation ////////////////////////////////
  always_comb begin
    misaligned_addr = 1'b0;
    dmem_be = 4'b0000;
    case (ex_if_type_i)  // 0x2 (word), 0x1 (halfword), 0x0 (byte)
      2'b00: begin  // Writing a byte
          case (data_addr_int[1:0])
            2'b00:   dmem_be = 4'b0001;
            2'b01:   dmem_be = 4'b0010;
            2'b10:   dmem_be = 4'b0100;
            2'b11:   dmem_be = 4'b1000;
            default: dmem_be = 4'b0000;
          endcase
      end

      2'b01: begin  // Writing a half-word
          case (data_addr_int[1:0])
            2'b00:   dmem_be = 4'b0011;
            2'b10:   dmem_be = 4'b1100;
            default: begin
                dmem_be = 4'b0000;
                misaligned_addr = 1'b1;
            end
          endcase
      end

      2'b10: begin  // Writing a word
          case (data_addr_int[1:0])
            2'b00:   dmem_be = 4'b1111;
            default: begin
                dmem_be = 4'b0000;
                misaligned_addr = 1'b1;
            end
          endcase
      end
      default: begin
          dmem_be = 4'b0000;
          misaligned_addr = 1'b1;
      end 
    endcase
  end


  ///////////////////////////////// dmem_req ////////////////////////////////
  always_ff @(posedge clk, negedge rst_n) begin
    if (!rst_n) begin
      dmem_req_q <= 1'b0;
      dmem_req_addr_q <= '0;
      dmem_req_we_q <= '0 ;
      dmem_req_be_q <= '0 ;
      dmem_req_wdata_q <= '0 ;
    end else if (ex_req_fire) begin
      dmem_req_q <= 1'b1;
      dmem_req_addr_q <= data_addr_int;
      dmem_req_we_q <= ex_if_we_i;
      dmem_req_be_q <= dmem_be ;
      dmem_req_wdata_q <= ex_if_wdata_i ;
    end else if (dmem_req_q && dmem_gnt_i) begin
      dmem_req_q <= 1'b0;  // request granted
      dmem_req_addr_q <= '0 ;
      dmem_req_we_q <= '0 ;
      dmem_req_be_q <= '0 ;
      dmem_req_wdata_q <= '0 ;
    end
  end


  ///////////////////////////////// DMEM Request Interface ////////////////////////////////
  always_comb begin : dmem_req
    dmem_req_o        = dmem_req_q;
    dmem_req_addr_o   = dmem_req_addr_q;
    dmem_req_we_o     = dmem_req_we_q;
    dmem_req_be_o     = dmem_req_be_q;
    dmem_req_wdata_o  = dmem_req_wdata_q;
  end

  ///////////////////////////////// Read Response Handling ////////////////////////////////
  always_ff @(posedge clk, negedge rst_n) begin
    if (!rst_n) begin
      wb_if_rdata_q   <= 32'b0;
      wb_if_rvalid_q  <= 1'b0;
    end else if (dmem_rvalid_i) begin
      wb_if_rdata_q   <= dmem_rsp_rdata_i;
      wb_if_rvalid_q  <= 1'b1;
    end else begin
      wb_if_rvalid_q  <= 1'b0;
    end
  end

  assign wb_if_rdata_o =  wb_if_rdata_q;
  assign wb_if_rvalid_o = wb_if_rvalid_q;

  ///////////////////////////////// Busy Logic ////////////////////////////////
  always_ff @(posedge clk, negedge rst_n) begin
    if (!rst_n) begin
      busy_q <= 1'b0;
    end else if (ex_req_fire) begin
      busy_q <= 1'b1;
    end else if (dmem_req_we_q && dmem_gnt_i) begin
      busy_q <= 1'b0;  // Write request granted
    end else if (!dmem_req_we_q && dmem_rvalid_i) begin
      busy_q <= 1'b0;  // Read request response received
    end
  end

endmodule

