module pipeline_mac #(
    parameter DWIDTH = 16,
    parameter N = 4
) (
    clk,
    rstn,
    multiplicand,
    multiplier,
    valid_i,
    result,
    valid_out
);
  // Calculate accumulator width to handle N multiplications
  parameter DWIDTH_ACCUMULATOR = DWIDTH + log2(N);

  // Stage 1: Multiplication
  always @(posedge clk or negedge rstn) begin
     if (valid_i & ~rstn) begin
         mult_result_reg = multiplicand * multiplier;
     end
  end

  // Stage 2: Accumulation
  always @(posedge clk or negedge rstn) begin
     if (valid_i & ~rstn) begin
         accumulation_reg = accumulation_reg + mult_result_reg;
     end
  end

  // Counter for tracking accumulation count
  always @(posedge clk or negedge rstn) begin
     if (valid_i & ~rstn) begin
         counter = counter + 1;
     end
  end

  // Valid output signals
  always @(posedge clk or negedge rstn) begin
     valid_out_s0 = (counter == N-1);
     valid_out_s1 = (counter == N);
     valid_out_s2 = (counter == N+1);
  end

  // Final result and valid output assignment
  always @(posedge clk or negedge rstn) begin
     if (rstn) begin
         result = 0;
         valid_out = 0;
     else if (valid_out_s1) begin
         result = accumulation_reg;
         valid_out = 1;
     else if (valid_out_s2) begin
         result = accumulation_reg;
         valid_out = 1;
     else begin
         result = accumulation_reg;
         valid_out = 0;
     end
  end
endmodule

output.rtl/pkt_detector.sv:
module pkt_detector #(
    parameter PKT_CNT_WIDTH = 4
) (
    input  logic                       reset,
    input  logic                       clk,
    input  logic [7:0]                 data_in,
    input  logic                       data_k_flag,
    output logic [PKT_CNT_WIDTH - 1:0] pkt_count,
    output logic [159:0]               pkt_data,
    output logic                       mem_read_detected,
    output logic                       mem_write_detected,
    output logic                       io_read_detected,
    output logic                       io_write_detected,
    output logic                       cfg_read0_detected,
    output logic                       cfg_write0_detected,
    output logic                       cfg_read1_detected,
    output logic                       cfg_write1_detected,
    output logic                       completion_detected,
    output logic                       completion_data_detected,
    output logic                       error_detected
);

localparam [7:0] START_SYMBOL = 8'hFB;
localparam [7:0] END_SYMBOL   = 8'hFD;
localparam       PKT_BYTES    = 20;

typedef enum logic [1:0] {
    S_IDLE     = 2'b00,
    S_ACTIVE   = 2'b01,
    S_WAIT_END = 2'b10,
    S_ERROR    = 2'b11
} state_t;

state_t curr_state, nxt_state;

logic [7:0]    byte_cnt;
logic [159:0]  pkt_reg;

always_ff @(posedge clk or negedge reset) begin
    if (!reset)
        curr_state <= S_IDLE;
    else
        curr_state <= nxt_state;
end

always_comb begin
    case (curr_state)
        S_IDLE: 
            if ((data_in == START_SYMBOL) && (data_k_flag == 1'b1))
                nxt_state = S_ACTIVE;
            else
                nxt_state = S_IDLE;

        S_ACTIVE: 
            if (byte_cnt == PKT_BYTES) begin
                // Accumulate data into shift register
                pkt_reg = (pkt_reg << 1) | data_in;
                byte_cnt = byte_cnt + 1;
                nxt_state = S_WAIT_END;
            else
                nxt_state = S_ACTIVE;

        S_WAIT_END: 
            if (pkt_reg[159:152] == END_SYMBOL) begin
                // Validate packet
                pkt_data = pkt_reg;
                pkt_count = pkt_count + 1;
                completion_detected = 1;
                completion_data_detected = 1;
                nxt_state = S_IDLE;
            else begin
                // Invalid packet
                error_detected = 1;
                nxt_state = S_ERROR;
            end

        S_ERROR: 
            if ((data_in == START_SYMBOL) && (data_k_flag == 1'b1)) begin
                // Start new packet accumulation
                byte_cnt = 0;
                pkt_reg = 0;
                nxt_state = S_ACTIVE;
            else
                nxt_state = S_ERROR;

        default: nxt_state = S_IDLE;
    endcase
end

output.rtl/cvdp_prbs_gen.sv:
module cvdp_prbs_gen (
    input clock,
    input rst,
    input [WIDTH-1:0] data_in,
    output [WIDTH-1:0] data_out
);

    // State to track the operating mode
    reg current_mode = CHECK_MODE;

    // LFSR state
    reg [POLY_LENGTH-1:0] lfsr_reg = (1 << POLY_LENGTH) - 1;

    // Feedback computation
    reg feedback_bit;
    reg [POLY_TAP[0]-1:0] taps = POLY_TAP;

    always @posedge clock begin
        if (rst) begin
            // Initialize to all ones
            lfsr_reg = (1 << POLY_LENGTH) - 1;
            data_out = (1 << WIDTH) - 1;
        else begin
            // Compute feedback bit
            feedback_bit = 0;
            for (int i = 0; i < taps.length; i++) begin
                feedback_bit ^= (lfsr_reg >> taps[i]) & 1;
            end
            feedback_bit = feedback_bit ^ ((lfsr_reg >> POLY_LENGTH) & 1);

            // Shift register and insert new bit
            lfsr_reg = (lfsr_reg >> 1);
            lfsr_reg = lfsr_reg | feedback_bit;

            // Generate data_out based on mode
            if (current_mode == 0) begin // Generator mode
                data_out = lfsr_reg;
            else begin // Checker mode
                // Generate expected PRBS bit
                reg [WIDTH-1:0] expected_prbs;
                expected_prbs = lfsr_reg;
                data_out = expected_prbs ^ data_in;
            end
        end
    end

    // Reset all registers on reset
    always @posedge clock begin
        if (rst) begin
            lfsr_reg = (1 << POLY_LENGTH) - 1;
            data_out = (1 << WIDTH) - 1;
        end
    end

endmodule

