module cvdp_copilot_register_file_2R1W #(
    parameter DATA_WIDTH = 32
) (
    input logic [DATA_WIDTH-1:0] din,
    input logic [4:0] wad1,
    input logic [4:0] rad1,
    input logic [4:0] rad2,
    input logic wen1,
    input logic ren1,
    input logic ren2,
    input logic clk,
    input logic resetn
    output logic [DATA_WIDTH-1:0] dout1,
    output logic [DATA_WIDTH-1:0] dout2,
    output logic collision
);

    // Register file memory with 32 entries of DATA_WIDTH-bit words
    logic [DATA_WIDTH-1:0] rf_mem [0:31];
    logic [31:0] rf_valid;                   // Validity of each register entry
    logic en_latch;    // Enable latch
    logic gated_clk;

    // Enable latch logic
    wire en_latch <= resetn;
    always_ff @(posedge clk or negedge resetn) begin
        en_latch = !resetn;
    end

    // Custom Clock Gating Logic
    wire (clk_en) = wen1 | ren1 | ren2;
    always_ff @(posedge clk_en or negedge resetn) begin
        if (!resetn) begin
            gated_clk = 0;
        else
            gated_clk = en_latch;
        end
    end

    // Register file initialization on reset
    integer i;
    initial begin
        i = 0;
        while (i < 32) begin
            rf_mem[i] <= 0;
            rf_valid[i] <= 0;
            i = i + 1;
        end
    end

    // Write operation logic
    always_ff @(posedge gated_clk or negedge resetn) begin
        if (!resetn) begin
            rf_valid[rad1] <= 0;
            rf_valid[rad2] <= 0;
        end
        else if (wen1) begin
            if (rad1 < 0 || rad2 < 0) begin
                rf_valid[rad1] <= 0;
                rf_valid[rad2] <= 0;
            else
                rf_valid[rad1] <= 1;
                rf_valid[rad2] <= 1;
                rf_mem[rad1] <= din;
                rf_mem[rad2] <= din;
            end
        end
    end

    // Read operation logic for port 1
    always_ff @(posedge gated_clk or negedge resetn) begin
        if (!resetn) begin
            dout1 <= 0;
        else if (ren1) begin
            if (rad1 >= 0 && rf_valid[rad1]) begin
                dout1 <= rf_mem[rad1];
            else
                dout1 <= 0;
            end
        else
            dout1 <= 0;
    end

    // Read operation logic for port 2
    always_ff @(posedge gated_clk or negedge resetn) begin
        if (!resetn) begin
            dout2 <= 0;
        else if (ren2) begin
            if (rad2 >= 0 && rf_valid[rad2]) begin
                dout2 <= rf_mem[rad2];
            else
                dout2 <= 0;
            end
        else
            dout2 <= 0;
    end

    // Collision detection logic
    always_ff @(posedge clk or negedge resetn) begin
        if (!resetn) begin
            collision <= 0;
        else begin
            if (rad1 == rad2 || (wad1 == rad1 && wad1 == rad2)) begin
                collision <= 1;
            else
                collision <= 0;
            end
        end
    end
endmodule

output.rtl/restore_division.sv:
module restoring_division (
    input wire [WIDTH-1:0] dividend,
    input wire [WIDTH-1:0] divisor,
    input wire clk,
    input wire rst,
    input wire start,
    output reg [WIDTH-1:0] quotient,
    output reg [WIDTH-1:0] remainder,
    output reg valid
);

    // Initialize remainder to 0
    reg [WIDTH-1:0] remainder = 0;

    // Quotient will be built bit by bit
    reg [WIDTH-1:0] quotient = 0;

    // Control signals for the algorithm
    reg start_new_iteration = 0;
    reg valid_after_iteration = 0;

    // Subtractor component
    subtractor subtractor (
        .a(remainder),
        .b(divisor),
        .valid(valid_after_iteration),
        .result(remainder)
    );

    // Main loop for division
    always_comb begin
        if (rst) begin
            // Reset all outputs
            remainder = 0;
            quotient = 0;
            valid = 0;
            // Wait for start to begin the process
            valid_after_iteration = 0;
        elsif start begin
            // Start the division process
            start_new_iteration = 1;
            valid = 0;
        end

        // Perform WIDTH iterations
        for (int i = 0; i < WIDTH; i = i + 1) begin
            // Shift remainder left and add next bit from dividend
            remainder = (remainder << 1) | (dividend >> (WIDTH - 1 - i)) & 1;

            // Subtract divisor and check result
            if (remainder >= divisor) begin
                // Quotient bit is 1
                quotient = quotient | (1 << (WIDTH - 1 - i));
                // Keep the result as new remainder
            else begin
                // Quotient bit is 0
                // Restore remainder by dropping the quotient bit
                remainder = remainder >> 1;
            end

            // Update validity after iteration
            valid_after_iteration = 1;
        end

        // After WIDTH iterations, set valid
        valid = valid_after_iteration;
    end

    // Cleanup after division
    always_comb begin
        if (rst) begin
            // Cleanup
            valid = 0;
        end
    end
endmodule

output.rtl/reverse_bits.v:
module reverse_bits(
    input [31:0] num_in,
    output [31:0] num_out
);
    reg [31:0] num_out;
    for (i = 0; i < 32; i = i + 1) begin
        num_out = (num_out << 1) | ((num_in >> (31 - i)) & 1);
    end
endmodule

