module round_robin_arbiter #(
    parameter N = 4
)(
    input  wire             clk,
    input  wire             rstn,
    input  wire [N-1:0]     req,   
    output reg  [N-1:0]     grant   
);

    reg [$clog2(N)-1:0] pointer;
    reg [$clog2(N)-1:0] pointer_next;
    reg found;

    integer i;
    always @(*) begin
        grant        = {N{1'b0}};
        pointer_next = pointer;

        if (req != 0) begin
           found = 1'b0;
            for (i = 0; i < N; i = i + 1) begin
                if (!found && req[(pointer + i) % N] == 1'b1) begin
                    grant[(pointer + i) % N] = 1'b1;

                    pointer_next = (pointer + i + 1) % N;
                    found        = 1'b1;                    
                end
            end
        end
    end

    always @(posedge clk or negedge rstn) begin
        if (!rstn) begin
            pointer <= 0;
        end else begin
            pointer <= pointer_next;
        end
    end

endmodule

output.rtl/round_robin_arbiter.sv:
module round_robin_arbiter #(
    parameter N = 4
    parameter TIMEOUT = 16
)(
    input  wire             clk,
    input  wire             rstn,
    input  wire [N-1:0]     req,   
    input  wire [N-1:0]     priority_level,
    input  wire [31:0]     timeout_counter0,
    input  wire [31:0]     timeout_counter1,
    input  wire [31:0]     timeout_counter2,
    input  wire [31:0]     timeout_counter3,
    output reg  [N-1:0]     grant   
);

    reg [$clog2(N)-1:0] pointer;
    reg [$clog2(N)-1:0] pointer_next;
    reg found;
    reg idle = 1'b0;
    reg [31:0] timeout_counter;
    integer i;

    // Initialize timeout counters
    initial begin
        timeout_counter0 = 0;
        timeout_counter1 = 0;
        timeout_counter2 = 0;
        timeout_counter3 = 0;
    end

    always @(*) begin
        // Set initial state based on priority level
        if (priority_level == 4'b1000) begin
            grant = {N{1'b0}};
            pointer_next = pointer;
            found = 0;
        else begin
            grant = {N{1'b0}};
            pointer_next = pointer;
            found = 0;
        end
    end

    if (req != 0) begin
        found = 0;
        for (i = 0; i < N; i = i + 1) begin
            if (!found && (priority_level[(pointer + i) % N] == 4'b1000)) begin
                grant[(pointer + i) % N] = 1'b1;
                pointer_next = (pointer + i + 1) % N;
                found = 1'b1;
            end else if (!found && timeout_counter[(pointer + i) % N] >= TIMEOUT) begin
                grant[(pointer + i) % N] = 1'b1;
                pointer_next = (pointer + i + 1) % N;
                found = 1'b1;
                timeout_counter[(pointer + i) % N] = 0;
            end else if (!found) begin
                timeout_counter[(pointer + i) % N] += 1;
            end
        end
    end

    always @(posedge clk or negedge rstn) begin
        if (!rstn) begin
            pointer <= 0;
        end else begin
            pointer <= pointer_next;
        end
    end

    // Update timeout counters
    if (found) begin
        timeout_counter0 = 0;
        timeout_counter1 = 0;
        timeout_counter2 = 0;
        timeout_counter3 = 0;
    end else begin
        timeout_counter0 += (req == 0 && (pointer == 0) ? 1 : 0);
        timeout_counter1 += (req == 0 && (pointer == 1) ? 1 : 0);
        timeout_counter2 += (req == 0 && (pointer == 2) ? 1 : 0);
        timeout_counter3 += (req == 0 && (pointer == 3) ? 1 : 0);
    end
endmodule

output.rtl/copilot_rs_232.sv:
module copilot_rs_232 (
    clock,
    reset_neg,
    tx_datain_ready,
    Present_Processing_Completed,
    tx_datain,
    tx_transmitter,
    tx_transmitter_valid
);
    // Parameters
    parameter HIGH = 1'b1;
    parameter LOW = 1'b0;
    parameter CLOCK_FREQ = 100000000; // 100MHz
    parameter BAUD_RATE = 115200;     // Default baud rate
    parameter REG_INPUT = 1;
    parameter BAUD_ACC_WIDTH = 16;

    // Inputs
    input reset_neg;
    input clock;
    input tx_datain_ready;
    input Present_Processing_Completed;
    input [7:0] tx_datain;

    // Outputs
    output tx_transmitter;
    output tx_transmitter_valid;

    // Internal signals
    reg tx_transmitter;
    reg [4:0] state; // 4-bit state machine
    wire baud_pulse;

    // Instantiate the Baud Rate Generator
    baud_rate_generator #(
        .BAUD_ACC_WIDTH(BAUD_ACC_WIDTH),
        .CLOCK_FREQ(CLOCK_FREQ),
        .BAUD_RATE(BAUD_RATE)
    ) baud_gen (
        .clock(clock),
        .reset_neg(reset_neg),
        .enable(tx_transmitter_valid),
        .baud_pulse(baud_pulse)
    );

    // Instantiate the Output Multiplexer
    always @ (posedge clock or negedge reset_neg) begin
        if (reset_neg == LOW) begin
            tx_transmitter <= HIGH;
            state <= 0;
        end else if (Present_Processing_Completed == HIGH) begin
            tx_transmitter <= HIGH;
            state <= 0;
        end else begin
            case (state)
                0: tx_transmitter <= HIGH;
                1: tx_transmitter <= tx_datain[0];
                2: tx_transmitter <= tx_datain[1];
                3: tx_transmitter <= tx_datain[2];
                4: tx_transmitter <= tx_datain[3];
                5: tx_transmitter <= tx_datain[4];
                6: tx_transmitter <= tx_datain[5];
                7: tx_transmitter <= tx_datain[6];
                8: tx_transmitter <= tx_datain[7];
                9: tx_transmitter <= LOW;
                default: tx_transmitter <= HIGH;
            endcase
            state <= (state + 1) % 10;
        end
    end

    // Baud Rate Generator Module
    module baud_rate_generator #(
        parameter CLOCK_FREQ = 100000000, // 100MHz
        parameter BAUD_RATE = 115200, // Default baud rate
        parameter BAUD_ACC_WIDTH = 16
    )
 (
    input clock,
    input reset_neg,
    input enable,
    output reg baud_pulse
);

    // Internal signals
    wire [BAUD_ACC_WIDTH:0] baud_acc;
    reg [BAUD_ACC_WIDTH:0] baud_inc;

    // Calculate the baud increment value
    assign baud_inc = ((BAUD_RATE << (BAUD_ACC_WIDTH - 4)) + (CLOCK_FREQ >> 5)) / (CLOCK_FREQ >> 4);

    // Baud rate increment and accumulation
    always @ (posedge clock) begin
        if (enable) begin
            baud_acc = (baud_acc + baud_inc) % (1 << BAUD_ACC_WIDTH);
            if (baud_acc >= (1 << BAUD_ACC_WIDTH)) begin
                baud_pulse = 1;
                baud_acc = 0;
            end else begin
                baud_pulse = 0;
            end
        end else begin
            baud_acc = 0;
            baud_pulse = 0;
        end
    end
endmodule

// Baud Rate Generator Module
module baud_rate_generator #(
    parameter CLOCK_FREQ = 100000000, // 100MHz
    parameter BAUD_RATE = 115200, // Default baud rate
    parameter BAUD_ACC_WIDTH = 16
)
 (
    input clock,
    input reset_neg,
    input enable,
    output reg baud_pulse
);

    // Internal signals
    wire [BAUD_ACC_WIDTH:0] baud_acc;
    reg [BAUD_ACC_WIDTH:0] baud_inc;

    // Calculate the baud increment value
    assign baud_inc = ((BAUD_RATE << (BAUD_ACC_WIDTH - 4)) + (CLOCK_FREQ >> 5)) / (CLOCK_FREQ >> 4);

    // Baud rate increment and accumulation
    always @ (posedge clock) begin
        if (enable) begin
            baud_acc = (baud_acc + baud_inc) % (1 << BAUD_ACC_WIDTH);
            if (baud_acc >= (1 << BAUD_ACC_WIDTH)) begin
                baud_pulse = 1;
                baud_acc = 0;
            end else begin
                baud_pulse = 0;
            end
        end else begin
            baud_acc = 0;
            baud_pulse = 0;
        end
    end
endmodule

output.rtl/run_length.sv:
module run_length
#(
    parameter DATA_WIDTH = 8
)
(
    input wire clk,
    input wire reset_n,
    input wire data_in,
    output reg data_out,
    output reg [$clog2(DATA_WIDTH):0] run_value,
    output reg valid
)
    reg [$clog2(DATA_WIDTH):0] run_length;
    reg prev_data_in;

    always @posedge (clk or reset_n) begin
        if (!reset_n) begin
            run_length <= 0;
            run_value <= 0;
            prev_data_in <= data_in;
            valid <= 0;
            data_out <= 0;
        else begin
            if (data_in != prev_data_in) begin
                valid <= 1;
                data_out <= prev_data_in;
                run_value <= run_length;
                run_length <= 0;
                prev_data_in <= data_in;
            else begin
                run_length <= run_length + 1;
                data_out <= data_out;
            end
        end
    end
end

module parallel_run_length
#(
    parameter DATA_WIDTH = 8,
    parameter NUM_STREAMS = 4
)
(
    input wire clk,
    input wire reset_n,
    input wire data_in[NUM_STREAMS-1:0],
    input wire stream_enable[NUM_STREAMS-1:0],
    output reg data_out[NUM_STREAMS-1:0],
    output reg run_value[((NUM_STREAMS * ($clog2(DATA_WIDTH)+1)) - 1):0],
    output reg valid[NUM_STREAMS-1:0]
);

    reg data_out_reg[NUM_STREAMS-1:0];
    reg run_value_reg[NUM_STREAMS-1:0];
    reg valid_reg[NUM_STREAMS-1:0];
    reg prev_data_in[NUM_STREAMS-1:0];
    reg run_length[NUM_STREAMS-1:0];

    always @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            for (int i = 0; i < NUM_STREAMS; i++) begin
                data_out_reg[i] = 0;
                run_value_reg[i] = 0;
                valid_reg[i] = 0;
                prev_data_in[i] = 0;
                run_length[i] = 0;
            end
            valid <= valid_reg;
            data_out <= data_out_reg;
        end
        else begin
            for (int i = 0; i < NUM_STREAMS; i++) begin
                if (stream_enable[i]) begin
                    if (data_in[i] == prev_data_in[i]) begin
                        if (run_length[i] == DATA_WIDTH) begin
                            run_value_reg[i] = run_length[i];
                        else if (run_length[i] < DATA_WIDTH) begin
                            run_length[i] = run_length[i] + 1;
                        else begin
                            run_length[i] = 1;
                        end
                    end
                    else begin
                        run_value_reg[i] = run_length[i];
                        run_length[i] = 1;
                    end
                    prev_data_in[i] = data_in[i];
                end
            end
            valid <= valid_reg;
            data_out <= data_out_reg;
        end
    end

    always @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            valid_reg <= (all(valid_reg));
            data_out_reg <= (all(data_out_reg));
        end
        else begin
            for (int i = 0; i < NUM_STREAMS; i++) begin
                if (stream_enable[i]) begin
                    if (run_length[i] == DATA_WIDTH || data_in[i] != prev_data_in[i]) begin
                        valid_reg[i] = 1;
                    end
                    else begin
                        valid_reg[i] = 0;
                    end
                end
            end
        end
    end
endmodule

input.rtl/deinter_block.sv:
module deinter_block #(
    parameter ROW_COL_WIDTH = 16,
    parameter SUB_BLOCKS    = 4,
    parameter DATA_WIDTH    = ROW_COL_WIDTH*ROW_COL_WIDTH,
    parameter OUT_DATA_WIDTH= 16,
    parameter WAIT_CYCLES   = 4
)(
    input  logic clk,
    input  logic rst_n,
    input  logic i_valid,
    input  logic [DATA_WIDTH-1:0] in_data, // Input: 256 bits
    output logic [OUT_DATA_WIDTH-1:0] out_data // Output: 256 bits rearranged
);

localparam CHUNK = 8;
localparam NBW_COUNTER = $clog2(SUB_BLOCKS) + 1;
localparam NBW_COUNTER_SUB_OUT = 2;

localparam OUT_CYCLES = 32;

localparam N_CYCLES = SUB_BLOCKS*DATA_WIDTH/OUT_DATA_WIDTH;
localparam NBW_COUNTER_OUTPUT = $clog2(N_CYCLES);
logic [NBW_COUNTER_OUTPUT-1:0] counter_output;

logic [NBW_COUNTER-1:0] counter_sub_blocks;
logic [NBW_COUNTER_SUB_OUT-1:0] counter_sub_out;

logic [DATA_WIDTH-1:0] in_data_reg [SUB_BLOCKS-1:0];
logic [DATA_WIDTH-1:0] out_data_intra_block [SUB_BLOCKS-1:0];
logic [DATA_WIDTH-1:0] out_data_intra_block_reg [SUB_BLOCKS-1:0];
logic [DATA_WIDTH-1:0] out_data_aux [SUB_BLOCKS-1:0];
logic start_intra;

always_ff @(posedge clk or negedge rst_n ) begin
   if(!rst_n) begin
      counter_sub_blocks <= {NBW_COUNTER{1'b0}};
      start_intra <= 0;
      for(int i = 0; i < SUB_BLOCKS; i++) begin
         in_data_reg[i] <= {DATA_WIDTH{1'b0}};
      end
   end
   else begin
      if(i_valid) begin
         in_data_reg[counter_sub_blocks] <= in_data;

         if(counter_sub_blocks == SUB_BLOCKS) begin
            counter_sub_blocks <= {NBW_COUNTER{1'b0}};
         end
         else begin
            start_intra <= 0;
            counter_sub_blocks <= counter_sub_blocks + 1;
         end
      end
      else if(counter_sub_blocks == SUB_BLOCKS) begin
         start_intra        <= 1;
         counter_sub_blocks <= {NBW_COUNTER{1'b0}};
      end
   end
end

always_ff @(posedge clk or negedge rst_n) begin
   if(!rst_n) begin
      for(int i = 0; i < SUB_BLOCKS; i++)
         out_data_intra_block_reg[i] <= {DATA_WIDTH{1'b0}};
   end
   else begin
      if(start_intra)
         for(int i = 0; i < SUB_BLOCKS; i++) 
            out_data_intra_block_reg[i] <= in_data_reg[i];
   end
end

logic [WAIT_CYCLES-1:0] start_intra_ff;
logic enable_output;

always_ff @(posedge clk or negedge rst_n) begin
   if(!rst_n) begin
      enable_output  <= 0;
      start_intra_ff <= 0;
   end
   else begin
      enable_output <= start_intra_ff[WAIT_CYCLES-1];
      start_intra_ff<= {start_intra_ff[WAIT_CYCLES-1:1],start_intra};
   end
end

always_ff @(posedge clk or negedge rst_n) begin
   if(!rst_n) begin
      for(int i = 0; i < SUB_BLOCKS; i++)
         out_data_aux[i] <= {DATA_WIDTH{1'b0}};
   end
   else begin
      if(start_intra) begin
         for(int i = 0; i < 32; i++) begin
            out_data_aux[0][(i+1)*CHUNK-1-:CHUNK] <= out_data_intra_block_reg[i%4][((i+1)*CHUNK)-1-:CHUNK];
            out_data_aux[1][(i+1)*CHUNK-1-:CHUNK] <= out_data_intra_block_reg[i%4][(((i+1)%OUT_CYCLES+1)*CHUNK)-1-:CHUNK];
            out_data_aux[2][(i+1)*CHUNK-1-:CHUNK] <= out_data_intra_block_reg[i%4][(((i+2)%OUT_CYCLES+1)*CHUNK)-1-:CHUNK];
            out_data_aux[3][(i+1)*CHUNK-1-:CHUNK] <= out_data_intra_block_reg[i%4][(((i+3)%OUT_CYCLES+1)*CHUNK)-1-:CHUNK];
         end
      end
   end
end

always_ff @(posedge clk or negedge rst_n) begin
   if(!rst_n) begin
      out_data        <= {DATA_WIDTH{1'b0}};      
      counter_sub_out <= {NBW_COUNTER_SUB_OUT{1'b0}};
      counter_output  <= {NBW_COUNTER_OUTPUT{1'b0}};     
   end
   else begin
      counter_sub_out <= counter_sub_out + 1;
      counter_output  <= counter_output  + 1;
      out_data        <= out_data_aux[counter_sub_out][((counter_output%(DATA_WIDTH/OUT_DATA_WIDTH) + 1))*OUT_DATA_WIDTH-1-:OUT_DATA_WIDTH];
   end
end

endmodule

