output.rtl/sdram_controller.sv:
module sdram_controller (clk, reset, addr, data_in, data_out, read, write, sdram_clk, sdramp_cke, sdram_cs, sdram_ras, sdram_cas, sdram_we, sdram_addr, sdram_ba, sdram_dq, dq_out);

   // State variables
   state_type state = INIT;
   state_type read_state = IDLE;
   state_type write_state = IDLE;
   state_type refresh_state = IDLE;

   // FSM transitions
   always_ff+ state begin
      case (read, write)
         default: state = IDLE; next_state = IDLE; endcase

         // Read command
         if (write) begin
             state = ACTIVATE;
             next_state = READ;
         end

         // Write command
         if (read) begin
             state = ACTIVATE;
             next_state = WRITE;
         end
   end

   // Read state
   always_ff+ read_state begin
      case (read, write)
         default: read_state = IDLE; next_read_state = IDLE; endcase

         // Read complete
         if (read) begin
             read_state = IDLE;
             next_read_state = IDLE;
         end
   end

   // Write state
   always_ff+ write_state begin
      case (read, write)
         default: write_state = IDLE; next_write_state = IDLE; endcase

         // Write complete
         if (write) begin
             write_state = IDLE;
             next_write_state = IDLE;
         end
   end

   // Auto-refresh state
   always_ff+ refresh_state begin
      if (reset) begin
          refresh_state = IDLE;
          next_refresh_state = IDLE;
      end
   end

   // Initialize SDRAM
   always_initial begin
      // Setup initial conditions
      // ...
   end

   // Control signals
   assign sdram_cs = (state == INIT) ? 1 : 0;
   assign sdram_ras = (state == ACTIVATE) ? 1 : 0;
   assign sdram_cas = (state == ACTIVATE) ? 1 : 0;
   assign sdram_we = (state == IDLE) ? 0 : 1;
   assign sdram_addr = addr;
   assign sdram_ba = 0;

   // Output data
   assign dq_out = data_out;

endmodule

output.rtl/alu_seq.v:
module alu_seq (
    input i_clk,          // Clock signal
    input i_rst_b,        // Active-low asynchronous reset
    input [3:0] i_operand_a, // 4-bit input operand A
    input [3:0] i_operand_b, // 4-bit input operand B
    input [2:0] i_opcode,    // 3-bit operation code
    input [7:0] i_key_in,    // 8-bit security key input
    output reg [7:0] o_result // 8-bit operation result
);

    reg [7:0] p_key = 0xAA; // Internal configurable security key

    always @ (i_rst_b, i_key_in, i_opcode) begin
        if (i_key_in != p_key) begin
            o_result = 8'b0;
        else begin
            case (i_opcode)
                000: o_result = i_operand_a + i_operand_b;
                001: o_result = i_operand_a - i_operand_b;
                010: o_result = i_operand_a * i_operand_b;
                011: o_result = i_operand_a & i_operand_b;
                100: o_result = i_operand_a | i_operand_b;
                101: o_result = ~i_operand_a;
                110: o_result = i_operand_a ^ i_operand_b;
                111: o_result = ~ (i_operand_a ^ i_operand_b);
                default: o_result = 8'b0;
            endcase
        end
    end

endmodule

output.rtl/secure_read_write_bus_interface.v:
module secure_read_write_bus_interface (
    input i_addr,
    input i_data_in,
    input i_key_in,
    input i_read_write_enable,
    input i_capture_pulse,
    input i_reset_bar,
    output o_data_out,
    output o_error
) 

    wire 
        ip [p_addr_width-1:0], 
        io [p_data_width-1:0];

    reg 
        ip_reg [p_addr_width-1:0], 
        io_reg [p_data_width-1:0],
        error_reg;

    parameter addr_width = p_addr_width;
    parameter data_width = p_data_width;

    always @ (posedge i_reset_bar) begin
        ip_reg = 0;
        io_reg = 0;
        error_reg = 1;
        o_error = 1;
    end

    always @ (posedge i_capture_pulse) begin
        if (i_key_in != p_configurable_key) begin
            error_reg = 1;
            io_reg = 0;
            o_error = 1;
        else begin
            if (i_read_write_enable == 1) begin
                ip_reg = i_addr;
            end else begin
                io_reg = i_data_in;
            end
            o_error = 0;
        end
    end

    o_data_out = io_reg;
    o_error = error_reg;

endmodule

output.rtl/secure_read_write_register_bank.v:
module secure_read_write_register_bank(
    input wire [p_address_width-1:0] i_addr,
    input wire [p_data_width-1:0] i_data_in,
    input wire i_read_write_enable,
    input wire i_capture_pulse,
    input wire i_rst_n,
    output wire [p_data_width-1:0] o_data_out
);

    // State variables
    reg state = 0;
    reg [p_address_width-1:0] addr = 0;
    reg [p_data_width-1:0] data = 0;

    // Unlock codes
    literal unlock_code_0 = p_unlock_code_0;
    literal unlock_code_1 = p_unlock_code_1;

    // Register array
    reg [p_address_width-1:0] registers = 0;

    // State machine
    always @(posedge i_capture_pulse) begin
        case (state)
            0:
                if (i_read_write_enable == 1 && addr == 0) begin
                    if (i_data_in == unlock_code_0) begin
                        addr = 1;
                        state = 1;
                    else begin
                        // Reset
                        state = 3;
                        addr = 0;
                        registers = 0;
                    end
                end else if (i_read_write_enable == 0 && addr == 0) begin
                    // Write to address 0
                    data = i_data_in;
                    addr = 1;
                end else if (i_read_write_enable == 1 && addr == 1) begin
                    if (i_data_in == unlock_code_1) begin
                        // Unlock complete
                        state = 2;
                        addr = 0;
                    else begin
                        // Reset
                        state = 3;
                        addr = 0;
                        registers = 0;
                    end
                end else if (i_rst_n) begin
                    // Reset
                    state = 3;
                    addr = 0;
                    registers = 0;
                end
            1:
                if (i_read_write_enable == 1 && addr == 1) begin
                    if (i_data_in == unlock_code_1) begin
                        // Unlock complete
                        state = 2;
                        addr = 0;
                    else begin
                        // Reset
                        state = 3;
                        addr = 0;
                        registers = 0;
                    end
                end else if (i_rst_n) begin
                    // Reset
                    state = 3;
                    addr = 0;
                    registers = 0;
                end
            2:
                // Unlock complete, allow read/write
                o_data_out = registers[addr];
            3:
                // Error state, output 0
                o_data_out = 0;
        endcase
    end

    // Register array implementation
    always @* begin
        registers[addr] = i_data_in;
    end

endmodule

output.rtl/secure_variable_timer.v:
module secure_variable_timer (
    input wire i_clk,           // Clock signal (rising-edge triggered)
    input wire i_rst_n,         // Active-low synchronous reset signal
    input wire i_data_in,       // Serial data input
    output reg [3:0] o_time_left, // 4-bit output showing remaining time during counting phase
    output reg o_processing,    // Asserted high when the timer is actively counting
    output reg o_completed,     // Asserted high when the timer completes its delay
    input wire i_ack            // Acknowledgment signal to reset after completion
);

    // Internal registers
    reg [3:0] delay;            // Holds the 4-bit delay value
    reg state;                  // State machine state (Idle, Configure Delay, Counting, Done)
    reg [31:0] counter;         // Counter for the delay cycles
    reg [3:0] time_left;        // Remaining time in delay

    // Initialize state and registers
    always_comb begin
        state = Idle;
        delay = 0;
        counter = 0;
        time_left = 0;
    end

    // State machine logic
    case(state)
        Idle:
            // Look for '1101' pattern
            if (i_data_in & 0b1101)
                state = Configure Delay;
            // Else stay in Idle

        Configure Delay:
            // Read next 4 bits as delay
            delay = i_data_in[3:0];
            // Transition to Counting state
            state = Counting;

        Counting:
            // Start counting
            counter = counter + 1;
            o_processing = 1;

            // Update time_left
            time_left = delay;
            while (counter < 1000) begin
                time_left = time_left - 1;
                counter = counter + 1;
            end
            // Once counter reaches 1000, decrement time_left for remaining cycles
            while (counter > 1000) begin
                time_left = time_left - 1;
                counter = counter + 1;
            end
            o_time_left = time_left;

            // When counter reaches (delay + 1)*1000, transition to Done state
            state = Done;

        Done:
            // Wait for acknowledgment
            if (i_ack)
                state = Idle;
    endcase

endmodule

output.rtl/serial_in_parallel_out_8bit.sv:
module serial_in_parallel_out_8bit (
    input clock,
    input serial_in,
    output parallel_out
);

    reg parallel_out = 8'b0;
    reg state = 0;

    always clock_edge begin
        state <= state + 1;
        if (state < 8)
            parallel_out = (parallel_out << 1) | serial_in;
        else
            parallel_out = parallel_out;
    end

endmodule

