    end

    always @(posedge clk) begin
        if(rinc_out) 
           byte_buf <= i_byte[7:1];
    end

    always @(posedge clk) begin
        if(rinc_out) 
            bp <= 4'b0;
        else 
            if(rinc_in & ~rempty_out) 
               bp <= bp + 1'b1;
    end

    //Other comb logic

    assign rde = bp[3];
    assign o_bit = byte_buf[bp];

endmodule

input.rtl/square_root.sv:
module square_root #(parameter WIDTH = 16) (
    input  wire [WIDTH-1:0] num,       
    output reg  [WIDTH/2-1:0] root     
);
    reg [WIDTH-1:0] remainder,square;         
    reg [WIDTH/2-1:0] test_bit, temp_square;        
    integer i,j;

    always @(*) 
    begin
        remainder = num;               
        root = 0;                      
        temp_square = 0;


        for (i = WIDTH/2-1; i >= 0; i = i - 1) 
        begin
            test_bit = 1'b1 << i;      
            temp_square = (root | test_bit);        
            square = 0; 
            for (j = 0; j < WIDTH; j = j + 1) 
            begin
              if (temp_square[j]) 
              begin 
                  square = square + (temp_square << j); 
              end 
            end

            if (square <= remainder) 
            begin
                root = root | test_bit; 
            end
        end
    end
endmodule

output.rtl/square_root_seq.sv:
module square_root_seq #(parameter WIDTH = 16) (
    input  wire [WIDTH-1:0] num,
    input  wire clock,
    input  wire rst,
    input  wire start,
    output reg [WIDTH/2-1:0] final_root,
    output reg done
);
    reg [WIDTH-1:0] remainder;
    reg [1:0] odd;
    reg [WIDTH/2-1:0] square_root;
    reg state;
    integer i;

    state initial, compute;

    always @posedge clock or posedge rst
    begin
        if (rst) 
            state = initial;
        else if (start) 
            state = compute;
        end
    end

    initial: 
        if (start) 
            remainder = num;
            square_root = 0;
            odd = 1;
            state = compute;
        end
    compute: 
        while (remainder >= odd) 
        begin
            remainder = remainder - odd;
            square_root = square_root + 1;
            odd = odd + 2;
        end
        done = 1;
        final_root = square_root;
    end
endmodule

output.rtl/static_branch_predict.sv:
module static_branch_predict(
    input [31:0] fetch_rdata_i,
    input [31:0] fetch_pc_i,
    input 1-bit fetch_valid_i,
    output 1-bit predict_branch_taken_o,
    output [31:0] predict_branch_pc_o
);

    // Extract immediate value
    wire [31:0] immediate;

    // Determine instruction type
    wire [31:0] instr_b_taken;

    // Always take jumps (JAL, JALR, C.J, C.JAL)
    if ((fetch_rdata_i[30:28] == 0x6F) || (fetch_rdata_i[30:28] == 0x67)) {
        predict_branch_taken_o = 1;
        predict_branch_pc_o = fetch_pc_i + immediate;
    } else if ((fetch_rdata_i[30:28] == 0x63) || (fetch_rdata_i[30:28] == 0x67)) {
        // For branches, check sign bit of immediate
        if (immediate[31] == 1) {
            predict_branch_taken_o = 1;
            predict_branch_pc_o = fetch_pc_i + immediate;
        } else {
            predict_branch_taken_o = 0;
            predict_branch_pc_o = fetch_pc_i;
        }
    } else {
        // Other instructions, no prediction
        predict_branch_taken_o = 0;
        predict_branch_pc_o = fetch_pc_i;
    }
endmodule

