module static_branch_predict (

  // Instruction from fetch stage
  input  logic [31:0] fetch_rdata_i,
  input  logic [31:0] fetch_pc_i,
  input  logic [31:0] register_addr_i,
  input  logic        fetch_valid_i,

  // Prediction for supplied instruction
  output logic        predict_branch_taken_o,
  output logic [31:0] predict_branch_pc_o
);
  logic [31:0] reg_addr;
  logic [31:0] imm_jal_type;
  logic [31:0] imm_jalr_type;
  logic [31:0] imm_b_type;
  logic [31:0] imm_cj_type;
  logic [31:0] imm_cb_type;

  logic [31:0] branch_imm;

  logic [31:0] instr;

  logic instr_jal;
  logic instr_jalr;
  logic instr_b;
  logic instr_cj;
  logic instr_cb;

  logic instr_b_taken;

  assign instr = fetch_rdata_i;
  assign reg_addr = register_addr_i;

  // Instruction decoding and immediate selection
  if (instr[6:0] == 0x6F) begin
    instr_jal = 1;
    imm_jal_type = instr[31:0];
    imm_jalr_type = 0;
    imm_b_type = 0;
    imm_cj_type = 0;
    imm_cb_type = 0;
  elsif (instr[6:0] == 0x67) begin
    instr_jalr = 1;
    imm_jal_type = 0;
    imm_jalr_type = instr[31:0];
    imm_b_type = 0;
    imm_cj_type = 0;
    imm_cb_type = 0;
  elsif (instr[6:0] == 0x63) begin
    instr_b = 1;
    imm_jal_type = 0;
    imm_jalr_type = 0;
    imm_b_type = instr[31:0];
    imm_cj_type = 0;
    imm_cb_type = 0;
  elsif (instr[6:0] == 0x1C) begin
    instr_cj = 1;
    imm_jal_type = 0;
    imm_jalr_type = 0;
    imm_b_type = 0;
    imm_cj_type = instr[31:0];
    imm_cb_type = 0;
  elsif (instr[6:0] == 0x1D) begin
    instr_cb = 1;
    imm_jal_type = 0;
    imm_jalr_type = 0;
    imm_b_type = 0;
    imm_cj_type = 0;
    imm_cb_type = instr[31:0];
  else begin
    branch_imm = imm_b_type;
  end

  // Branch taken decision
  instr_b_taken = 1;
  if (instr_jal || instr_jalr || instr_cj) begin
    instr_b_taken = 1;
  elsif instr_b begin
    instr_b_taken = ~imm_b_type[31];
  elsif instr_cj begin
    instr_b_taken = ~imm_cj_type[31];
  elsif instr_cb begin
    instr_b_taken = ~imm_cb_type[31];
  end

  // Predicted branch taken output
  predict_branch_taken_o = instr_b_taken;

  // Predicted branch target address
  predict_branch_pc_o = branch_imm + fetch_pc_i;

module static_branch_predict(
  // Instruction from fetch stage
  input  logic [31:0] fetch_rdata_i,
  input  logic [31:0] fetch_pc_i,
  input  logic [31:0] register_addr_i,
  input  logic        fetch_valid_i,

  // Prediction for supplied instruction
  output logic        predict_branch_taken_o,
  output logic [31:0] predict_branch_pc_o,

  // Additional outputs
  output logic [7:0]  predict_confidence_o,   // Confidence level in prediction
  output logic        predict_exception_o,    // Exception/misalignment detection
  output logic [2:0]  predict_branch_type_o,  // Type of branch
  output logic [31:0] predict_branch_offset_o // Calculated branch offset
);

  logic [31:0] reg_addr;
  logic [31:0] imm_jal_type;
  logic [31:0] imm_jalr_type;
  logic [31:0] imm_b_type;
  logic [31:0] imm_cj_type;
  logic [31:0] imm_cb_type;
  logic [31:0] instr;

  logic instr_jal;
  logic instr_jalr;
  logic instr_b;
  logic instr_cj;
  logic instr_cb;

  logic instr_b_taken;

  // Assign instruction to instr
  instr = fetch_rdata_i;

  // Determine instruction type and calculate imms
  case(instr[6:0])
    7'h6F: instr_jal = 1;
    7'h67: instr_jalr = 1;
    7'h63: instr_b = 1;
    7'h62: instr_cj = 1;
    7'h61: instr_cb = 1;
    default: instr_jal = instr_jalr = instr_b = instr_cj = instr_cb = 0;
  endcase

  // Calculate imms based on instruction type
  if(instr_jal)
    imm_jal_type = { {12{instr[31]}}, instr[19:12], instr[20], instr[30:21], 1'b0 };
  else if(instr_jalr)
    imm_jalr_type = {{20{instr[31]}}, instr[31:20]} + reg_addr;
  else if(instr_b)
    imm_b_type = { {19{instr[31]}}, instr[31], instr[7], instr[30:25], instr[11:8], 1'b0 };
  else if(instr_cj)
    imm_cj_type = { {20{instr[12]}}, instr[12], instr[8], instr[10:9], instr[6], instr[7], instr[2], instr[11], instr[5:3], 1'b0 };
  else if(instr_cb)
    imm_cb_type = { {23{instr[12]}}, instr[12], instr[6:5], instr[2], instr[11:10], instr[4:3], 1'b0 };
  else
    imm_jal_type = imm_jalr_type = imm_b_type = imm_cj_type = imm_cb_type = 0;

  // Set confidence levels
  if(instr_jal || instr_jalr)
    predict_confidence_o = 100;
  else if(instr_b)
    predict_confidence_o = (imm_b_type[31] == 1) ? 90 : 50;
  else if(instr_cj || instr_cb)
    predict_confidence_o = (imm_cj_type[31] == 1) ? 90 : 50;
  else
    predict_confidence_o = 0;

  // Set branch taken flag
  predict_branch_taken_o = predict_confidence_o > 50;

  // Calculate branch target address
  case(instr_jal)
    predict_branch_offset_o = imm_jal_type;
    break;
  case(instr_jalr)
    predict_branch_offset_o = imm_jalr_type;
    break;
  case(instr_b)
    predict_branch_offset_o = imm_b_type;
    break;
  case(instr_cj)
    predict_branch_offset_o = imm_cj_type;
    break;
  case(instr_cb)
    predict_branch_offset_o = imm_cb_type;
    break;
  default
    predict_branch_offset_o = 0;
  endcase

  // Exception detection
  if(!fetch_valid_i || (instr_b_taken && imm_b_type[31] == 0))
    predict_exception_o = 1;
  else
    predict_exception_o = 0;

output.rtl/strobe_divider.sv:
module strobe_divider #(
    parameter MaxRatio_g = 10,
    parameter Latency_g = 1
)(
    input wire Clk,
    input wire Rst,
    input wire [log2ceil(MaxRatio_g)-1:0] In_Ratio,
    input wire In_Valid,
    output reg Out_Valid,
    input wire Out_Ready
);

    function integer log2ceil;
        input integer value;
        integer i;
        begin
            log2ceil = 1;
            for (i = 0; (2 ** i) < value; i = i + 1)
                log2ceil = i + 1;
        end
    endfunction

    reg [log2ceil(MaxRatio_g)-1:0] r_Count, r_OutValid;
    reg r_next_Count, r_next_OutValid;
    reg OutValid_v;

    always @* begin
        if (Rst) {
            r_next_Count = 0;
            r_next_OutValid = 0;
            OutValid_v = 0;
        } else if (In_Ratio == 0) {
            r_next_Count = 0;
            r_next_OutValid = 1;
            OutValid_v = 1;
        } else {
            if (In_Ratio == r_Count) {
                r_next_Count = 0;
                r_next_OutValid = 1;
            } else if (In_Ratio != 0 && In_Valid) {
                r_next_Count = r_Count + 1;
                r_next_OutValid = r_OutValid;
            } else {
                r_next_Count = r_Count;
                r_next_OutValid = r_OutValid;
            }
            OutValid_v = r_OutValid;
        }
    end

    always @posedge Clk begin
        if (Rst) {
            r_Count = 0;
            r_OutValid = 0;
        } else if (In_Ratio == 0) {
            r_Count = 0;
            r_OutValid = 1;
        } else {
            if (In_Ratio == r_Count) {
                r_Count = 0;
                r_OutValid = 1;
            } else if (In_Ratio != 0 && In_Valid) {
                r_Count = r_Count + 1;
            }
        }
    end

    always @* begin
        if (Out_Ready) {
            r_next_Count = 0;
            r_next_OutValid = 0;
        }
    end

    Out_Valid = OutValid_v;
endmodule

