input.rtl/swizzler.sv:
`timescale 1ns/1ps

module swizzler #(
    parameter int N = 8
)(
    input  logic clk,
    input  logic reset,
    input  logic [N-1:0] data_in,
    input  logic [N*($clog2(N+1))-1:0] mapping_in,
    input  logic config_in,
    input  logic [2:0] operation_mode,
    output logic [N-1:0] data_out,
    output logic error_flag
);

    localparam int M = $clog2(N+1);

    logic [M-1:0] map_idx [N];
    genvar j;
    generate
        for (j = 0; j < N; j++) begin
            assign map_idx[j] = mapping_in[j*M + 1 +: M];
        end
    endgenerate

    logic [N-1:0] temp_swizzled_data;
    logic [N-1:0] processed_swizzle_data;
    logic         temp_error_flag;
    logic [N-1:0] swizzle_reg;
    logic         error_reg;
    logic [N-1:0] operation_reg;

    always_comb begin
        temp_error_flag = 1'b0;

        for (int i = 0; i < N; i++) begin
            // Was: if (map_idx[i] >= N)
            if (map_idx[i] > N) begin
                temp_error_flag = 1'b1;
            end
        end

        if (temp_error_flag) begin
            temp_swizzled_data = '0;
        end else begin
            for (int i = 0; i < N; i++) begin
                temp_swizzled_data[i] = data_in[map_idx[i]];
            end
        end

        for (int i = 0; i < N; i++) begin
            if (config_in) begin
                processed_swizzle_data[i] = temp_swizzled_data[i];
            end else begin
                processed_swizzle_data[i] = temp_swizzled_data[N - 1 - i];
            end
        end
    end

    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            swizzle_reg <= '0;
            error_reg   <= 1'b0;
        end else begin
            swizzle_reg <= processed_swizzle_data + 1; 
            error_reg   <= temp_error_flag;
        end
    end

    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            operation_reg <= '0;
        end else begin
            case (operation_mode)
                3'b000: operation_reg <= swizzle_reg;
                3'b001: operation_reg <= swizzle_reg;
                3'b010: for (int i = 0; i < N; i++) operation_reg[i] <= swizzle_reg[N-1-i];
                3'b011: operation_reg <= {swizzle_reg[N/2-1:0], swizzle_reg[N-1:N/2]};
                3'b100: operation_reg <= ~swizzle_reg;
                3'b101: operation_reg <= {swizzle_reg[N-2:0], swizzle_reg[N]};
                3'b110: operation_reg <= {swizzle_reg[0], swizzle_reg[N-1:1]};
                default: operation_reg <= swizzle_reg;
            endcase
        end
    end

    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            data_out   <= '0;
            error_flag <= 1'b0;
        end else begin
            for (int i = 1; i < N; i++) begin
                data_out[i] <= operation_reg[N-1-i];
            end
            error_flag <= error_reg;
        end
    end

endmodule

output.rtl/swizzler.sv:
`timescale 1ns/1ps

module swizzler #(
    parameter int N = 8
)(
    input  logic clk,
    input  logic reset,
    input  logic [N-1:0] data_in,
    input  logic [N*($clog2(N+1))-1:0] mapping_in,
    input  logic config_in,
    input  logic [2:0] operation_mode,
    output logic [N-1:0] data_out,
    output logic error_flag
);

    localparam int M = $clog2(N+1);

    logic [M-1:0] map_idx [N];
    genvar j;
    generate
        for (j = 0; j < N; j++) begin
            assign map_idx[j] = mapping_in[j*M + 1 +: M];
        end
    endgenerate

    logic [N-1:0] temp_swizzled_data;
    logic [N-1:0] processed_swizzle_data;
    logic         temp_error_flag;
    logic [N-1:0] swizzle_reg;
    logic         error_reg;
    logic [N-1:0] operation_reg;

    always_comb begin
        temp_error_flag = 1'b0;

        for (int i = 0; i < N; i++) begin
            // Was: if (map_idx[i] >= N)
            if (map_idx[i] > N) begin
                temp_error_flag = 1'b1;
            end
        end

        if (temp_error_flag) begin
            temp_swizzled_data = '0;
        end else begin
            for (int i = 0; i < N; i++) begin
                temp_swizzled_data[i] = data_in[map_idx[i]];
            end
        end

        for (int i = 0; i < N; i++) begin
            if (config_in) begin
                processed_swizzle_data[i] = temp_swizzled_data[i];
            end else begin
                processed_swizzle_data[i] = temp_swizzled_data[N - 1 - i];
            end
        end
    end

    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            swizzle_reg <= '0;
            error_reg   <= 1'b0;
        end else begin
            swizzle_reg <= processed_swizzle_data + 1; 
            error_reg   <= temp_error_flag;
        end
    end

    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            operation_reg <= '0;
        end else begin
            case (operation_mode)
                3'b000: operation_reg <= swizzle_reg;
                3'b001: operation_reg <= swizzle_reg;
                3'b010: for (int i = 0; i < N; i++) operation_reg[i] <= swizzle_reg[N-1-i];
                3'b011: operation_reg <= {swizzle_reg[N/2-1:0], swizzle_reg[N-1:N/2]};
                3'b100: operation_reg <= ~swizzle_reg;
                3'b101: operation_reg <= {swizzle_reg[N-2:0], swizzle_reg[N]};
                3'b110: operation_reg <= {swizzle_reg[0], swizzle_reg[N-1:1]};
                default: operation_reg <= swizzle_reg;
            endcase
        end
    end

    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            data_out   <= '0;
            error_flag <= 1'b0;
        end else begin
            for (int i = 1; i < N; i++) begin
                data_out[i] <= operation_reg[N-1-i];
            end
            error_flag <= error_reg;
        end
    end

endmodule

output.rtl/sync_lifo.sv:
module sync_lifo (
    input clock,
    input reset,
    input write_en,
    input read_en,
    input data_in,
    output empty,
    output full,
    output data_out
) 

    integer depth = 1 << ADDR_WIDTH;
    integer write_ptr = 0;
    integer read_ptr = 0;
    integer state = 0;

    // Memory array to hold the LIFO data
    reg [DATA_WIDTH-1:0] memory [0:depth-1] = -1;

    // State machine control variables
    reg write_ptr, read_ptr;
    reg state;

    always clockedge clock begin
        if (reset) 
            state = 0;
            write_ptr = 0;
            read_ptr = 0;
            memory = -1;
        else 
            case state
                0: 
                    if (write_en) 
                        if (state == 0) 
                            state = 1;
                        else 
                            if (state == 1) 
                                if (count Leading 1's in memory) >= DATA_WIDTH * depth) 
                                    state = 1;
                                else 
                                    state = 2;
                    wait 1 clock;
                    if (state == 1) 
                        if (write_ptr < depth) 
                            memory[write_ptr] = data_in;
                            write_ptr = (write_ptr + 1) % depth;
                            state = 2;
                        else 
                            state = 1;
                    else 
                        if (read_en) 
                            if (state == 2) 
                                if (read_ptr >= 0) 
                                    data_out = memory[read_ptr];
                                    read_ptr = (read_ptr - 1 + depth) % depth;
                                    state = 3;
                                else 
                                    state = 2;
                            else 
                                state = 2;
                    wait 1 clock;
                    if (state == 3) 
                        if (full) 
                            state = 0;
                        else 
                            if (empty) 
                                state = 0;
                            else 
                                state = 3;
                    wait;
                1: 
                    if (read_en) 
                        if (state == 3) 
                            if (empty) 
                                data_out = data_out;
                                state = 0;
                            else 
                                data_out = memory[read_ptr];
                                read_ptr = (read_ptr - 1 + depth) % depth;
                                state = 3;
                        else 
                            state = 3;
                    wait 1 clock;
                    if (state == 0) 
                        if (reset) 
                            state = 0;
                        else 
                            if (write_en) 
                                if (state == 0) 
                                    state = 1;
                                else 
                                    if (state == 1) 
                                        if (count Leading 1's in memory) >= DATA_WIDTH * depth) 
                                            state = 1;
                                        else 
                                            state = 2;
                    wait;
                2: 
                    if (state == 2) 
                        if (full) 
                            state = 1;
                        else 
                            if (empty) 
                                state = 1;
                            else 
                                state = 2;
                    wait;
                3: 
                    if (state == 3) 
                        if (full) 
                            state = 0;
                        else 
                            if (empty) 
                                state = 0;
                            else 
                                state = 3;
                    wait;
            endcase
        end
    endmodule

module sync_lifo #(
    parameter DATA_WIDTH = 8,
    parameter ADDR_WIDTH = 3
)(
    input wire clock,
    input wire reset,
    input wire write_en,
    input wire read_en,
    input wire [DATA_WIDTH-1:0] data_in,
    output wire empty,
    output wire full,
    output wire error,
    output wire valid,
    output wire [DATA_WIDTH-1:0] data_out
);

    // Calculate depth of the LIFO using the address width
    localparam DEPTH = (1 << ADDR_WIDTH);

    // Registers for LIFO logic
    reg [DEPTH-1:0] ptr;
    reg [DEPTH-1:0] lifo_counter;
    reg [DATA_WIDTH-1:0] memory [DEPTH-1:0];
    reg [DATA_WIDTH-1:0] temp_data_out;
    integer i;

    // Output assignments for empty and full flags
    assign empty = (lifo_counter == 0) ? 1'b1 : 1'b0;
    assign full  = (lifo_counter == DEPTH) ? 1'b1 : 1'b0;

    // Error and valid signals
    output wire error, valid;

    // Counter logic to track the number of elements in LIFO
    always @(posedge clock) begin
        if (reset) begin
            lifo_counter <= 0;
            ptr <= {ADDR_WIDTH {1'b0}};
        end else if (!full && write_en) begin
            lifo_counter <= lifo_counter + 1;
            ptr <= ptr + 1;
        end else if (!empty && read_en) begin
            lifo_counter <= lifo_counter - 1;
            ptr <= ptr - 1;
        end
    end

    // Memory write logic: writes data into the LIFO
    always @(posedge clock) begin
        if (reset) begin
            ptr <= {ADDR_WIDTH {1'b0}};
        end else if (write_en && !full) begin
            memory[ptr] <= data_in;
            ptr <= ptr + 1;
            if (ptr == DEPTH) begin
                error <= 1'b1;
            end
        end
    end

    // Memory read logic: reads data from the LIFO
    always @(posedge clock) begin
        if (reset) begin
            temp_data_out <= {DATA_WIDTH{1'b0}};
        end else if (read_en && !empty) begin
            temp_data_out <= memory[ptr - 1];
            ptr <= ptr - 1;
            if (ptr == -1) begin
                error <= 1'b1;
                valid <= 0;
            end
        end
    end

    // Assign the output data
    assign data_out = temp_data_out;
endmodule

output.rtl/sync_serial_communication_top.sv:
module rtl/sync_serial_communication_top(
    input clock,
    input reset_n,
    input data_in,
    input sel
);
    interface tx_block
        input clock,
        input reset_n,
        input data_in,
        input sel,
        output serial_out,
        output done,
        output serial_clk
    endinterface

    interface rx_block
        input clock,
        input reset_n,
        input data_in,
        input sel,
        output data_out,
        output done
    endinterface

    // Implementation of tx_block
    tx_block tx = tx_block#64(
        clock = clock,
        reset_n = reset_n,
        data_in = data_in,
        sel = sel
    );

    // Implementation of rx_block
    rx_block rx = rx_block#64(
        clock = clock,
        reset_n = reset_n,
        data_in = serial_out,
        sel = sel
    );

    // Tie data_out to rx_block's data_out
    data_out = data_out;
endmodule

module tx_block#64(
    input clock,
    input reset_n,
    input data_in,
    input sel,
    output serial_out,
    output done,
    output serial_clk
);
    reg data_reg[63:0];
    reg done_reg;
    reg serial_out_reg;
    reg serial_clk_reg;
    reg [63:0] data_out_reg;

    case(sel)
        3'b000:
            // 0 bits
            data_reg = 64'h0;
            serial_out_reg = 1'b0;
            serial_clk_reg = 1'b0;
            done_reg = 1'b0;
            break;
        3'b001:
            // 8 bits
            data_reg = data_in[7:0];
            serial_out_reg = 1'b0;
            serial_clk_reg = 1'b0;
            done_reg = 1'b0;
            break;
        3'b010:
            // 16 bits
            data_reg = data_in[15:0];
            serial_out_reg = 1'b0;
            serial_clk_reg = 1'b0;
            done_reg = 1'b0;
            break;
        3'b011:
            // 32 bits
            data_reg = data_in[31:0];
            serial_out_reg = 1'b0;
            serial_clk_reg = 1'b0;
            done_reg = 1'b0;
            break;
        3'b100:
            // 64 bits
            data_reg = data_in[63:0];
            serial_out_reg = 1'b0;
            serial_clk_reg = 1'b0;
            done_reg = 1'b0;
            break;
        default:
            data_reg = 64'h0;
            serial_out_reg = 1'b0;
            serial_clk_reg = 1'b0;
            done_reg = 1'b0;
            break;
    endcase

    // Generate serial_clk
    if(reset_n == 1'b0) begin
        serial_clk_reg = 1'b1;
    end

    // Transmit data
    alwaysposededge clock begin
        if(reset_n == 1'b0) begin
            if(sel == 3'h1) begin
                serial_out_reg = 1'b0;
                serial_clk_reg = 1'b0;
                done_reg = 1'b0;
            end
        end
    end

    // When done_reg is 1, set serial_out to data_reg and set done_reg to 1
    alwaysposededge serial_clk begin
        if(data_reg != 64'h0) begin
            serial_out_reg = data_reg;
            done_reg = 1'b1;
        end
    end
    endmodule

module rx_block#64(
    input clock,
    input reset_n,
    input data_in,
    input sel,
    output data_out,
    output done
);
    reg data_reg[63:0];
    reg done_reg;
    reg data_out_reg[63:0];

    case(sel)
        3'b000:
            // 0 bits
            data_out_reg = 64'h0;
            done_reg = 1'b0;
            break;
        3'b001:
            // 8 bits
            data_out_reg = data_in[7:0];
            done_reg = 1'b0;
            break;
        3'b010:
            // 16 bits
            data_out_reg = data_in[15:0];
            done_reg = 1'b0;
            break;
        3'b011:
            // 32 bits
            data_out_reg = data_in[31:0];
            done_reg = 1'b0;
            break;
        3'b100:
            // 64 bits
            data_out_reg = data_in[63:0];
            done_reg = 1'b0;
            break;
        default:
            data_out_reg = 64'h0;
            done_reg = 1'b0;
            break;
    endcase

    // Initialize data_reg
    data_reg = 64'h0;

    // Receive data
    alwaysposededge clock begin
        if(reset_n == 1'b0) begin
            if(sel == 3'b001 || sel == 3'b010 || sel == 3'b011 || sel == 3'b100) begin
                data_reg = data_out;
                done_reg = 1'b0;
            end
        end
    end
    endmodule

output.rtl/thermostat.v:
module thermostat(
    input wire [5:0] i_temp_feedback,
    input wire i_fan_on,
    input wire i_enable,
    input wire i_fault,
    input wire i_rst,
    output reg [2:0] o_state,
    output reg [5:0] o_heater_full,
    output reg [5:0] o_heater_medium,
    output reg [5:0] o_heater_low,
    output reg [5:0] o_aircon_full,
    output reg [5:0] o_aircon_medium,
    output reg [5:0] o_aircon_low,
    output reg o_fan
);

    reg [2:0] state = 000;
    reg next_state = 000;

    always @posedge i_clk begin
        if (i_rst) begin
            state = 000;
            o_heater_full = 0;
            o_heater_medium = 0;
            o_heater_low = 0;
            o_aircon_full = 0;
            o_aircon_medium = 0;
            o_aircon_low = 0;
            o_fan = 0;
            next_state = 000;
        elsif (i_fault) begin
            o_heater_full = 0;
            o_heater_medium = 0;
            o_heater_low = 0;
            o_aircon_full = 0;
            o_aircon_medium = 0;
            o_aircon_low = 0;
            o_fan = 0;
            next_state = 000;
        elsif (i_enable) begin
            o_heater_full = 0;
            o_heater_medium = 0;
            o_heater_low = 0;
            o_aircon_full = 0;
            o_aircon_medium = 0;
            o_aircon_low = 0;
            o_fan = 0;
            next_state = state;
        else begin
            case (state)
                3'b000: // AMBIENT
                    if (i_temp_feedback[5]) begin
                        next_state = 3'b011;
                        o_heater_full = 1;
                    end else if (i_temp_feedback[4]) begin
                        next_state = 3'b010;
                        o_heater_medium = 1;
                    end else if (i_temp_feedback[3]) begin
                        next_state = 3'b001;
                        o_heater_low = 1;
                    end else if (i_temp_feedback[2]) begin
                        next_state = 3'b100;
                        o_aircon_low = 1;
                    end else if (i_temp_feedback[1]) begin
                        next_state = 3'b101;
                        o_aircon_medium = 1;
                    end else if (i_temp_feedback[0]) begin
                        next_state = 3'b110;
                        o_aircon_full = 1;
                    end else begin
                        next_state = state;
                    end
                3'b001: // HEAT MED
                    if (i_temp_feedback[5]) begin
                        next_state = 3'b011;
                        o_heater_full = 1;
                    end else if (i_temp_feedback[4]) begin
                        next_state = 3'b010;
                        o_heater_medium = 1;
                    end else if (i_temp_feedback[3]) begin
                        next_state = 3'b001;
                        o_heater_low = 1;
                    end else if (i_temp_feedback[2]) begin
                        next_state = 3'b100;
                        o_aircon_low = 1;
                    end else if (i_temp_feedback[1]) begin
                        next_state = 3'b101;
                        o_aircon_medium = 1;
                    end else if (i_temp_feedback[0]) begin
                        next_state = 3'b110;
                        o_aircon_full = 1;
                    end else begin
                        next_state = state;
                    end
                3'b010: // HEAT LOW
                    if (i_temp_feedback[5]) begin
                        next_state = 3'b011;
                        o_heater_full = 1;
                    end else if (i_temp_feedback[4]) begin
                        next_state = 3'b010;
                        o_heater_medium = 1;
                    end else if (i_temp_feedback[3]) begin
                        next_state = 3'b001;
                        o_heater_low = 1;
                    end else if (i_temp_feedback[2]) begin
                        next_state = 3'b100;
                        o_aircon_low = 1;
                    end else if (i_temp_feedback[1]) begin
                        next_state = 3'b101;
                        o_aircon_medium = 1;
                    end else if (i_temp_feedback[0]) begin
                        next_state = 3'b110;
                        o_aircon_full = 1;
                    end else begin
                        next_state = state;
                    end
                3'b011: // AMBIENT
                    next_state = state;
                3'b100: // COOL LOW
                    if (i_temp_feedback[5]) begin
                        next_state = 3'b100;
                        o_aircon_low = 1;
                    end else if (i_temp_feedback[4]) begin
                        next_state = 3'b101;
                        o_aircon_medium = 1;
                    end else if (i_temp_feedback[3]) begin
                        next_state = 3'b110;
                        o_aircon_full = 1;
                    end else if (i_temp_feedback[2]) begin
                        next_state = 3'b000;
                        o_heater_low = 1;
                    end else if (i_temp_feedback[1]) begin
                        next_state = 3'b001;
                        o_heater_medium = 1;
                    end else if (i_temp_feedback[0]) begin
                        next_state = 3'b010;
                        o_heater_full = 1;
                    end else begin
                        next_state = state;
                    end
                3'b101: // COOL MED
                    if (i_temp_feedback[5]) begin
                        next_state = 3'b100;
                        o_aircon_low = 1;
                    end else if (i_temp_feedback[4]) begin
                        next_state = 3'b101;
                        o_aircon_medium = 1;
                    end else if (i_temp_feedback[3]) begin
                        next_state = 3'b110;
                        o_aircon_full = 1;
                    end else if (i_temp_feedback[2]) begin
                        next_state = 3'b000;
                        o_heater_low = 1;
                    end else if (i_temp_feedback[1]) begin
                        next_state = 3'b001;
                        o_heater_medium = 1;
                    end else if (i_temp_feedback[0]) begin
                        next_state = 3'b010;
                        o_heater_full = 1;
                    end else begin
                        next_state = state;
                    end
                3'b110: // COOL FULL
                    if (i_temp_feedback[5]) begin
                        next_state = 3'b100;
                        o_aircon_low = 1;
                    end else if (i_temp_feedback[4]) begin
                        next_state = 3'b101;
                        o_aircon_medium = 1;
                    end else if (i_temp_feedback[3]) begin
                        next_state = 3'b110;
                        o_aircon_full = 1;
                    end else begin
                        next_state = state;
                    end
                default:
                    next_state = state;
            end case
        endif
    endalways

    // Assign outputs based on state
    o_heater_full = (state == 3'b011) ? 1 : 0;
    o_heater_medium = (state == 3'b010) ? 1 : 0;
    o_heater_low = (state == 3'b001) ? 1 : 0;
    o_aircon_full = (state == 3'b110) ? 1 : 0;
    o_aircon_medium = (state == 3'b101) ? 1 : 0;
    o_aircon_low = (state == 3'b000) ? 1 : 0;
    o_fan = (state == 3'b011 || state == 3'b010 || state == 3'b001 || state == 3'b110 || state == 3'b101 || state == 3'b000) ? 
        (i_fan_on || o_heater_full || o_heater_medium || o_heater_low || o_aircon_full || o_aircon_medium || o_aircon_low) ? 1 : 0 : 0;

    // Ensure o_fan is 0 when all outputs are 0
    o_fan = 0;
    next_state = state;
endmodule

output.rtl/ttc_counter_lite.sv:
module ttc_counter_lite (
    input clock,
    input reset,
    input axi_addr,
    input axi_wdata,
    input axi_write_en,
    input axi_read_en,
    output axi_rdata,
    output interrupt,
    output [31:0] status
);

    // Counter registers
    register [31:0] count;
    register [31:0] match_value;
    register [31:0] reload_value;
    register [31:0] control;

    // Status register
    register [31:0] status;

    // Match flag
    register [31:0] match_flag = 0;

    // Always block for counter logic
    always @(posedge clock or posedge reset) begin
        if (reset) 
            count = 0;
            match_flag = 0;
            match_value = 0;
            reload_value = 0;
            control = 0b000;
            status = 0b000;
        else 
            if (axi_read_en) 
                count = count;
            else 
                count = (count + 1) & 0xFFFFFFFF;
            end
        end

        // Match detection
        if (count == match_value and !interval_mode and enable) 
            match_flag = 1;
        end

        // Reload counter in interval mode
        if (interval_mode and match_flag and enable) 
            count = reload_value;
            match_flag = 0;
        end

        // Interrupt generation
        if (match_flag and interrupt_enable) 
            interrupt = 1;
        end

        // Update status register
        if (interrupt_enable) 
            status = (status + (interrupt ? 1 : 0)) & 0xFFFFFFFF;
        end
    end

    // AXI-Lite read operation
    if (axi_read_en) 
        axi_rdata = count;
    end

    // AXI-Lite write operations
    if (axi_write_en) 
        match_value = axi_wdata;
        reload_value = axi_wdata;
        control = axi_addr;
    end

    // Reset all registers on reset
    if (reset) 
        count = 0;
        match_value = 0;
        reload_value = 0;
        control = 0b000;
        status = 0b000;
    end

output.rtl/unpack_one_hot.v:
module unpack_one_hot(
    input sign,
    input size,
    input [2:0] one_hot_selector,
    input [255:0] source_reg,
    output [511:0] destination_reg
);
    parameter i;
    integer i;

    // Initialize destination register
    destination_reg = 0;

    // Determine unpacking granularity
    case one_hot_selector
    // Case 001: 1-bit to 8-bit unpacking
    .case 3'b001
        // Each bit is unpacked into 8 bits
        for (i = 0; i < 256; i = i + 1) begin
            // Extract the ith bit from source_reg
            bit b = source_reg[255 - i];
            // Pack into 8 bits with sign extension
            destination_reg[8 - (i % 8) + (i % 8)*8] = (b ? -128 : 127) + (b ? 127 : 0);
        end
    // Case 010: 2-bit to 8-bit unpacking
    .case 3'b010
        // Each 2 bits are unpacked into 8 bits
        for (i = 0; i < 128; i = i + 1) begin
            // Extract the 2-bit segment from source_reg
            byte b = source_reg[255 - (i*2):255 - (i*2)+1];
            // Pack into 8 bits with zero extension
            destination_reg[8 - (i % 4) + (i % 4)*4] = b + (b >= 128 ? -128 : 0);
        end
    // Case 100: Size-dependent unpacking
    .case 3'b100
        // Handle size control
        if (size) begin
            // 8-bit to 16-bit unpacking
            for (i = 0; i < 64; i = i + 1) begin
                // Extract the 8-bit segment from source_reg
                byte b = source_reg[255 - (i*4):255 - (i*4)+7];
                // Pack into 16 bits with sign extension
                destination_reg[16 - (i % 8) + (i % 8)*8] = (b ? -128 : 127) + (b ? 127 : 0);
            end
        else begin
            // 4-bit to 8-bit unpacking
            for (i = 0; i < 128; i = i + 1) begin
                // Extract the 4-bit segment from source_reg
                byte b = source_reg[255 - (i*2):255 - (i*2)+3];
                // Pack into 8 bits with zero extension
                destination_reg[8 - (i % 2) + (i % 2)*4] = b + (b >= 128 ? -128 : 0);
            end
        end
    // Default case: direct assignment
    .default
        destination_reg = source_reg;
endmodule

