                red       <= {color_in[7:5], 5'd0};
                green     <= {color_in[4:2], 5'd0};
                blue      <= {color_in[1:0], 6'd0};
            end
            else begin
                red       <= 8'd0;
                green     <= 8'd0;
                blue      <= 8'd0;
        end
    end


    assign clk = clock;
    assign sync = 1'b0;
    assign blank = hsync & vsync;

    assign next_x = (h_state == H_ACTIVE_STATE) ? h_counter : 10'd0;
    assign next_y = (v_state == V_ACTIVE_STATE) ? v_counter : 10'd0;

endmodule

output.rtl/virtual2physical_tlb.sv:
module virtual2physical_tlb #(parameter ADDR_WIDTH = 8, PAGE_WIDTH = 8, TLB_SIZE = 4, PAGE_TABLE_SIZE = 16) (
    input clk,
    input reset,
    input [ADDR_WIDTH-1:0] virtual_address,
    output [PAGE_WIDTH-1:0] physical_address,
    output hit, miss
);
    wire tlb_write_enable, flush, ready;
    wire [PAGE_WIDTH-1:0] page_table_entry;
    TLB #(.TLB_SIZE(TLB_SIZE), .ADDR_WIDTH(ADDR_WIDTH), .PAGE_WIDTH(PAGE_WIDTH)) tlb (
        .clk(clk),
        .reset(reset),
        .virtual_address(virtual_address),
        .tlb_write_enable(tlb_write_enable),
        .flush(flush),
        .page_table_entry(page_table_entry),
        .physical_address(physical_address),
        .hit(hit),
        .miss(miss)
    );

    PageTableHandler #(.ADDR_WIDTH(ADDR_WIDTH), .PAGE_WIDTH(PAGE_WIDTH), .PAGE_TABLE_SIZE(PAGE_TABLE_SIZE)) page_table_handler(
        .clk(clk),
        .reset(reset),
        .miss(miss),
        .virtual_page(virtual_address),
        .page_table_entry(page_table_entry),
        .ready(ready)
    );

    ControlUnit control_unit (
        .clk(clk),
        .reset(reset),
        .hit(hit),
        .miss(miss),
        .ready(ready),
        .tlb_write_enable(tlb_write_enable),
        .flush(flush)
    );
endmodule

module TLB #(parameter TLB_SIZE = 4, ADDR_WIDTH = 8, PAGE_WIDTH = 8) (
    input clk,
    input reset,
    input [ADDR_WIDTH-1:0] virtual_address,
    input tlb_write_enable,
    input flush,
    input [PAGE_WIDTH-1:0] page_table_entry,
    output reg [PAGE_WIDTH-1:0] physical_address,
    output reg hit,
    output reg miss
);
    // TLB Storage
    reg [ADDR_WIDTH-1:0] virtual_tags[TLB_SIZE-1:0];
    reg [PAGE_WIDTH-1:0] physical_pages[TLB_SIZE-1:0];
    reg [TLB_SIZE-1:0] valid_bits;
    reg [log2(TLB_SIZE)-1:0] replacement_index;
    integer i;

    // TLB Write Enablement and Replacement Logic
    always_comb begin
        hit = 0;
        miss = 1;
        physical_address = 0;

        if (reset) begin
            // Initialize TLB
            valid_bits = 8'h1;
            replacement_index = 0;
        end else if (tlb_write_enable) begin
            // Check for a match in TLB
            hit = 1;
            for (i = 0; i < TLB_SIZE; i = i + 1) begin
                if (virtual_address == virtual_tags[i]) begin
                    physical_address = physical_pages[i];
                    valid_bits[i] = 1;
                    break;
                end
            end
        end else begin
            // TLB miss - need to replace
            miss = 1;
            // Find least recently used (LRU) entry
            replacement_index = 0;
            for (i = 0; i < TLB_SIZE; i = i + 1) begin
                if (!valid_bits[i]) begin
                    replacement_index = i;
                    break;
                end
            end
            // Replace the LRU entry
            virtual_tags[replacement_index] = virtual_address;
            physical_pages[replacement_index] = page_table_entry;
            valid_bits[replacement_index] = 0;
            replaced = 1;
        end
    end
endmodule

module PageTableHandler #(parameter ADDR_WIDTH = 8, PAGE_WIDTH = 8, PAGE_TABLE_SIZE = 16) (
    input clk,
    input reset,
    input miss,
    input [ADDR_WIDTH-1:0] virtual_page,
    output reg [PAGE_WIDTH-1:0] page_table_entry,
    output reg ready
);
    // Parameterized Page Table Memory
    reg [PAGE_WIDTH-1:0] page_table_memory [0:PAGE_TABLE_SIZE-1];
 assign   page_table_entry = page_table_memory[virtual_page];  
    always @(posedge clk or posedge reset) begin
        if (reset) begin
            // Initialize Page Table Memory during reset
            page_table_memory[0] <= 8'h0;
            page_table_memory[1] <= 8'h1;
            page_table_memory[2] <= 8'h2;
            page_table_memory[3] <= 8'h3;  
            page_table_memory[4] <= 8'h4;
            page_table_memory[5] <= 8'h5;
            page_table_memory[6] <= 8'h6;
            page_table_memory[7] <= 8'h7;
            page_table_memory[8] <= 8'h8;  
            page_table_memory[9] <= 8'h9;
            page_table_memory[10] <= 8'hA;
            page_table_memory[11] <= 8'hB;  
            page_table_memory[12] <= 8'hC;
            page_table_memory[13] <= 8'hD;
            page_table_memory[14] <= 8'hE;
            page_table_memory[15] <= 8'hF;          
            ready <= 0;
        end else if (miss) begin
            // Fetch the physical page number from the simulated page table         
            ready <= 1; // Indicate the entry is ready
        end else begin
            ready <= 0;
        end
    end
endmodule

module ControlUnit (
    input clk,
    input reset,
    input hit,
    input miss,
    input ready,
    output reg tlb_write_enable,
    output reg flush
);
    reg [1:0] state;

    localparam IDLE = 2'b00,
               FETCH = 2'b01,
               UPDATE = 2'b10;

    always begin
        if (reset) begin
            state = IDLE;
            tlb_write_enable = 0;
            flush = 0;
        end else if (hit) begin
            state = FETCH;
            tlb_write_enable = 0;
            flush = 0;
        end else if (miss) begin
            state = UPDATE;
            tlb_write_enable = 1;
            flush = 0;
        end else begin
            state = IDLE;
            tlb_write_enable = 0;
            flush = 0;
        end
    end
endmodule

output.rtl/wishbone_to_ahb_bridge.sv:
module wishbone_to_ahb_bridge(
    input wire [31:0] addr_i,
    input wire [31:0] data_i,
    input wire [3:0] sel_i,
    input wire rst_i,
    input wire cyc_i,
    input wire stb_i,
    input wire we_i,
    output wire [31:0] data_o,
    output wire ack_o,
    input wire hclk,
    input wire hreset_n,
    output wire [1:0] htrans,
    output wire [2:0] hsize,
    output wire [2:0] hburst,
    output wire hwrite,
    output wire haddr,
    output wire hwdata
);

    // FSM states
    enum state { IDLE, NON-SEQUENTIAL, BUSY };
    reg state = IDLE;

    // Address calculation
    reg [31:0] ahb_addr;

    // Data conversion
    reg [31:0] ahb_data;

    // Transaction control
    reg [1:0] htrans_val = 0;
    reg [2:0] hsize_val = 0;
    reg [2:0] hburst_val = 0;

    // Clock and reset handling
    always_comb begin
        if (rst_i || hreset_n) begin
            state = IDLE;
            htrans_val = 0;
            hsize_val = 0;
            hburst_val = 0;
            haddr = 0;
            hwdata = 0;
            ack_o = 0;
        end else begin
            case (state)
                IDLE: 
                    if (cyc_i) begin
                        // Handle read transaction
                        if (sel_i[0] & sel_i[1] & sel_i[2]) begin
                            // Byte operation
                            ahb_addr = addr_i;
                            hsize_val = 8;
                            htrans_val = 0;
                            hburst_val = 0;
                            hwdata = data_i;
                        end else if (sel_i[1] & sel_i[2]) begin
                            // Halfword operation
                            ahb_addr = addr_i;
                            hsize_val = 16;
                            htrans_val = 0;
                            hburst_val = 0;
                            hwdata = data_i[15:0] | (data_i[16:31] << 1);
                        end else if (sel_i[2]) begin
                            // Word operation
                            ahb_addr = addr_i;
                            hsize_val = 32;
                            htrans_val = 0;
                            hburst_val = 0;
                            hwdata = data_i[31:0];
                        end else begin
                            // Default to byte operation
                            ahb_addr = addr_i;
                            hsize_val = 8;
                            htrans_val = 0;
                            hburst_val = 0;
                            hwdata = data_i;
                        end
                        state = NON-SEQUENTIAL;
                    end
                NON-SEQUENTIAL: 
                    if (cyc_i) begin
                        // Handle write transaction
                        ahb_addr = (addr_i << 2) | sel_i;
                        hsize_val = 4 * (sel_i[0] ? 1 : 0) + 2 * (sel_i[1] ? 1 : 0) + (sel_i[2] ? 1 : 0);
                        htrans_val = 1;
                        hburst_val = 3'b000;
                        hwrite = we_i;
                        ack_o = 0;
                        state = BUSY;
                    end else begin
                        state = IDLE;
                    end
                BUSY: 
                    if (cyc_i) begin
                        if (hready) begin
                            ack_o = 1;
                            state = IDLE;
                        end
                    end else begin
                        state = IDLE;
                    end
            endcase
        end
    end

    // Convert data to AHB format
    always_comb begin
        if (sel_i[0]) begin // Byte
            ahb_data = data_i;
        else if (sel_i[1]) begin // Halfword
            ahb_data = data_i[15:0] | (data_i[16:31] << 1);
        else if (sel_i[2]) begin // Word
            ahb_data = data_i[31:0];
        else begin // Default to byte
            ahb_data = data_i;
        end
    end

    // Assign calculated values
    ahb_addr = ahb_addr;
    htrans = htrans_val;
    hsize = hsize_val;
    hburst = hburst_val;
    hwrite = hwrite;
    hwdata = ahb_data;
endmodule

output.rtl/Word_Change_Pulse.sv:
module Word_Change_Pulse#(
    parameter DATA_WIDTH = 8
) (
    input  wire                  clk,
    input  wire                  reset,
    input  wire [DATA_WIDTH-1:0] data_in,
    input  wire [DATA_WIDTH-1:0] mask,
    input  wire [DATA_WIDTH-1:0] match_pattern,
    input  wire                  enable,
    input  wire                  latch_pattern,
    output reg                   word_change_pulse,
    output reg                   pattern_match_pulse,
    output reg [DATA_WIDTH-1:0] latched_pattern
);

    wire [DATA_WIDTH-1:0] change_pulses;
    wire [DATA_WIDTH-1:0] masked_data_in;
    reg [DATA_WIDTH-1:0] masked_change_pulses;
    reg [DATA_WIDTH-1:0] latched_match_pattern;
    reg match_detected;

    genvar i;
    reg [DATA_WIDTH-1:0] prev_masked_data_in;

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            masked_data_in <= {DATA_WIDTH{1'b0}};
            masked_change_pulses <= {DATA_WIDTH{1'b0}};
            word_change_pulse <= 1'b0;
            match_detected <= 1'b0;
            pattern_match_pulse <= 1'b0;
            latched_pattern <= {DATA_WIDTH{1'b0}};
            latched_match_pattern <= {DATA_WIDTH{1'b0}};
        end else if (enable) begin
            if (latch_pattern) begin
                latched_match_pattern <= match_pattern;
            end
            masked_data_in <= data_in & mask;
            // Instantiate Bit_Change_Detector modules
            for (i = 0; i < DATA_WIDTH; i++) begin
                Bit_Change_Detector#(i+1) bit_chd (
                    .clk(clk),
                    .reset(reset),
                    .bit_in(data_in[i]),
                    .mask(mask[i]),
                    .change_pulse(masked_change_pulses[i])
                );
            end
            // Collect change pulses
            change_pulses <= masked_change_pulses;
            // Check for any change
            if (change_pulses) begin
                match_detected <= 1;
            end
            // Check for pattern match
            if (match_detected && latched_match_pattern == masked_data_in) begin
                pattern_match_pulse <= 1;
            end
        end else begin
            // No operation when enable is low
        end
    end
endmodule

module Bit_Change_Detector (
    input  wire  clk,
    input  wire  reset,
    input  wire  bit_in,
    output reg  change_pulse
);

    reg bit_in_d;
    reg prev_bit;
    reg change;

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            bit_in_d <= 0;
            prev_bit <= 0;
            change <= 0;
        end else begin
            bit_in_d <= bit_in;
            prev_bit <= bit_in_d;
        end
    end

    always @(*) begin
        change <= (bit_in_d != prev_bit);
        change_pulse <= change;
    end
endmodule

output.rtl/Data_Reduction.sv:
module Data_Reduction
#(
    parameter [2:0] REDUCTION_OP = 3'b000,
    parameter DATA_WIDTH         = 4,
    parameter DATA_COUNT         = 4,
    localparam TOTAL_INPUT_WIDTH = DATA_WIDTH * DATA_COUNT
)
(
    input  wire [TOTAL_INPUT_WIDTH-1:0] data_in,
    output reg  [DATA_WIDTH-1:0]        reduced_data_out
);

    generate
        genvar bit_index;

        for (bit_index = 0; bit_index < DATA_WIDTH; bit_index = bit_index + 1) begin : bit_processing
            wire [DATA_COUNT-1:0] extracted_bits;

            for (i = 0; i < DATA_COUNT; i = i + 1) begin
                extracted_bits[i] = data_in[bit_index + i * DATA_WIDTH];
            end

            Bitwise_Reduction #(.bit_count(DATA_COUNT), .op(REDUCTION_OP)) (extracted_bits, reduced_data_out[bit_index]);
        end
    endgenerate

endmodule


module Bitwise_Reduction
#(
    parameter [2:0] REDUCTION_OP = 3'b000,
    parameter BIT_COUNT          = 4
)
(
    input  wire [BIT_COUNT-1:0] input_bits,
    output reg                  reduced_bit
);

    localparam [2:0] AND_OP  = 3'b000;
    localparam [2:0] OR_OP   = 3'b001;
    localparam [2:0] XOR_OP  = 3'b010;
    localparam [2:0] NAND_OP = 3'b011;
    localparam [2:0] NOR_OP  = 3'b100;
    localparam [2:0] XNOR_OP = 3'b101;

    reg temp_result;

    always @(*) begin
        temp_result = input_bits[0];

        for (i = 1; i < BIT_COUNT; i = i + 1) begin
            case (REDUCTION_OP)
                AND_OP, NAND_OP  : temp_result = temp_result & input_bits[i];
                OR_OP,  NOR_OP   : temp_result = temp_result | input_bits[i];
                XOR_OP, XNOR_OP  : temp_result = temp_result ^ input_bits[i];
                default          : temp_result = temp_result & input_bits[i];
            endcase
        end

        reduced_bit = temp_result;
    end
endmodule

input.rtl/Data_Reduction.sv:
module Data_Reduction
#(
    parameter [2:0] REDUCTION_OP = 3'b000, // Default operation: AND
    parameter DATA_WIDTH         = 4,      // Width of each data element
    parameter DATA_COUNT         = 4,      // Number of data elements
    localparam TOTAL_INPUT_WIDTH = DATA_WIDTH * DATA_COUNT
)
(
    input  wire [TOTAL_INPUT_WIDTH-1:0] data_in,
    output reg  [DATA_WIDTH-1:0]        reduced_data_out
);

    generate
        genvar bit_index;

        // Iterate over each bit position within a single data word
        for (bit_index = 0; bit_index < DATA_WIDTH; bit_index = bit_index + 1) begin : bit_processing
            wire [DATA_COUNT-1:0] extracted_bits;

            // Extract bit at `bit_index` from each data word
            genvar data_index;
            for (data_index = 0; data_index < DATA_COUNT; data_index = data_index + 1) begin : bit_extraction
                assign extracted_bits[data_index] = data_in[(data_index * DATA_WIDTH) + bit_index];
            end

            // Perform reduction on the extracted bits
            Bitwise_Reduction
            #(
                .REDUCTION_OP (REDUCTION_OP),
                .BIT_COUNT    (DATA_COUNT)
            )
            reducer_instance
            (
                .input_bits  (extracted_bits),
                .reduced_bit (reduced_data_out[bit_index])
            );
        end
    endgenerate

endmodule


module Bitwise_Reduction
#(
    parameter [2:0] REDUCTION_OP = 3'b000, // Default operation: AND
    parameter BIT_COUNT          = 4       // Number of bits to reduce
)
(
    input  wire [BIT_COUNT-1:0] input_bits,
    output reg                  reduced_bit
);

    // Reduction Operation Codes
    localparam [2:0] AND_OP  = 3'b000;
    localparam [2:0] OR_OP   = 3'b001;
    localparam [2:0] XOR_OP  = 3'b010;
    localparam [2:0] NAND_OP = 3'b011;
    localparam [2:0] NOR_OP  = 3'b100;
    localparam [2:0] XNOR_OP = 3'b101;

    integer i;
    reg temp_result; // Intermediate result

    always @(*) begin
        // Initialize result with the first bit
        temp_result = input_bits[0];

        // Reduce bits using the selected operation
        for (i = 1; i < BIT_COUNT; i = i + 1) begin
            case (REDUCTION_OP)
                AND_OP, NAND_OP  : temp_result = temp_result & input_bits[i];
                OR_OP,  NOR_OP   : temp_result = temp_result | input_bits[i];
                XOR_OP, XNOR_OP  : temp_result = temp_result ^ input_bits[i];
                default          : temp_result = temp_result & input_bits[i];
            endcase
        end

        // Apply final inversion if required
        case (REDUCTION_OP)
            NAND_OP : reduced_bit = ~temp_result;
            NOR_OP  : reduced_bit = ~temp_result;
            XNOR_OP : reduced_bit = ~temp_result;
            default : reduced_bit = temp_result;
        endcase
    end
endmodule

output.rtl/Data_Reduction.sv:
module Bit_Difference_Counter
#(
    parameter [2:0] BIT_WIDTH = 4, // Width of each input vector
    parameter [2:0] COUNT_WIDTH = 3 // Width to represent count
)
(
    input  wire [BIT_WIDTH-1:0] input_A,
    input  wire [BIT_WIDTH-1:0] input_B,
    output reg [COUNT_WIDTH-1:0] bit_difference_count
);

    // Perform bitwise XOR to find differing bits
    Data_Reduction
    #(
        .REDUCTION_OP (3'b001), // XOR operation
        .DATA_WIDTH (BIT_WIDTH),
        .DATA_COUNT (BIT_WIDTH)
    )
    reduced_data_out (
        .data_in (input_A ^ input_B)
        .reduced_data_out (bit_difference_count)
    );
endmodule

output.rtl/write_buffer_merge.sv:
module write_buffer_merge #(
  parameter INPUT_DATA_WIDTH  = 32,                                     // Width of input data
  parameter INPUT_ADDR_WIDTH  = 16,                                     // Width of input address
  parameter BUFFER_DEPTH      = 8,                                      // Depth of the write buffer
  parameter OUTPUT_DATA_WIDTH = INPUT_DATA_WIDTH * BUFFER_DEPTH,        // Width of merged output data
  parameter OUTPUT_ADDR_WIDTH = INPUT_ADDR_WIDTH - $clog2(BUFFER_DEPTH) // Width of merged output address
) (
  input  logic                         clk,          // Clock signal
  input  logic                         srst,         // Synchronous reset (active high)
  input  logic                         wr_en_in,     // Write enable input
  input  logic [INPUT_ADDR_WIDTH-1:0]  wr_addr_in,   // Write address input
  input  logic [INPUT_DATA_WIDTH-1:0]  wr_data_in,   // Write data input
  output logic                         wr_en_out,    // Write enable output
  output logic [OUTPUT_ADDR_WIDTH-1:0] wr_addr_out,  // Write address output
  output logic [OUTPUT_DATA_WIDTH-1:0] wr_data_out   // Write data output
);

  // Internal signals for buffer tracking and management
  logic [$clog2(BUFFER_DEPTH)-1:0]      write_count;     // Counter for the number of writes in the buffer
  logic [OUTPUT_ADDR_WIDTH-1:0]         base_addr;       // Base address for the merged writes
  logic [OUTPUT_DATA_WIDTH-1:0]         merged_data;     // Buffer to hold merged data
  logic [$clog2(BUFFER_DEPTH)-1:0]      write_complete;  // Signal to indicate that the buffer is full and ready to output

  generate
    if (BUFFER_DEPTH > 1) begin
      // Write count logic: Counts the number of writes in the buffer
      always_ff @(posedge clk) begin
        if (srst)
          write_count <= '0;
        else if (wr_en_in)
          write_count <= write_count + 1;  // Increment count on write enable
      end

      // Base address logic: Captures the address of the first write in the buffer
      always_ff @(posedge clk) begin
        if (srst)
          base_addr <= '0;
        else if (wr_addr_in[INPUT_ADDR_WIDTH - $clog2(BUFFER_DEPTH):0]) // Mask to get base address
          base_addr <= wr_addr_in[INPUT_ADDR_WIDTH - $clog2(BUFFER_DEPTH):0];
      end

      // Merged data logic: Concatenates incoming data into the buffer
      always_ff @(posedge clk) begin
        if (srst)
          merged_data <= '0;
        else if (wr_en_in)
          merged_data <= (merged_data >> INPUT_DATA_WIDTH) | wr_data_in;
      end

      // Write completion logic: Indicates when the buffer is full
      always_ff @(posedge clk) begin
        if (srst)
          write_complete <= 1'b0;
        else if ((write_count == (BUFFER_DEPTH - 1)) && wr_en_in)
          write_complete <= 1'b1;  // Assert completion when buffer is full
        else
          write_complete <= 1'b0;
      end

      // Output logic when buffer is full
      always_ff @(posedge clk) begin
        if (write_complete) begin
          wr_en_out <= 1;
          wr_addr_out <= base_addr;
          wr_data_out <= merged_data;
        end else begin
          wr_en_out <= 0;
          wr_addr_out <= 0;
          wr_data_out <= 0;
        end
      end
    end else begin
      // Pass-through logic for buffer depth 1
      always_ff @(posedge clk) begin
        if (wr_en_in)
          wr_en_out <= 1;
          wr_addr_out <= wr_addr_in;
          wr_data_out <= wr_data_in;
        else
          wr_en_out <= 0;
          wr_addr_out <= 0;
          wr_data_out <= 0;
      end
    end
  endgenerate

endmodule

input.rtl/ddm_cache.sv:
module ddm_cache (
  input  logic        clk,           // Posedge clock
  input  logic        rst_n,         // Asynchronous Negedge reset
  input  logic [31:0] cpu_addr,      // Memory address emitted by the CPU
  input  logic [31:0] cpu_dout,      // Data emitted by CPU
  input  logic        cpu_strobe,    // CPU status signal to Cache to indicate it is going to perform a read or write operation
  input  logic        cpu_rw,        // cpu_rw == 1, Memory Write Operation ; cpu_rw == 0 , Memory Read Operation
  input  logic        uncached,      // uncached == 1 , IO port is accessed ; uncached == 0, Memory is accessed
  input  logic [31:0] mem_dout,      // Data emitted by memory
  input  logic        mem_ready,     // Memory is ready with the read data
  output logic [31:0] cpu_din,       // CPU Data coming from Memory through Cache
  output logic [31:0] mem_din,       // Memory Data coming from CPU through Cache
  output logic        cpu_ready,     // Cache is ready with data to be provided to CPU
  output logic        mem_strobe,    // Cache Status signal to Memory to indicate it is going to perform a read or write operation
  output logic        mem_rw,        // mem_rw == 1, Memory Write Operation ; mem_rw == 0 , Memory Read Operation
  output logic [31:0] mem_addr,      // Memory address to be accessed, emitted by the Cache
  output logic        cache_hit,     // Indicates a memory location is available in the cache
  output logic        cache_miss,    // Indicates a memory location is not available in the cache
  output logic [31:0] d_data_dout     // Data at a cache index
);

  logic         d_valid [0:63];
  logic [23:0]  d_tags  [0:63];
  logic [31:0]  d_data  [0:63];

  logic [23:0] tag;
  logic [5:0]  index;

  logic [31:0] cache_din;   
  logic        cache_write; 
  logic [23:0] d_tag_out;
  logic        valid;
  logic [31:0] cache_dout;

  integer i;

  assign tag   = cpu_addr[31:8];
  assign index = cpu_addr[7:2]; 
  assign cache_write = ~uncached & (cpu_rw | cache_miss & mem_ready); 

  always_ff @(posedge clk or negedge rst_n) begin
      if (!rst_n) begin
          for (i = 0; i < 64; i = i + 1) begin
              d_valid[i] <= 0;
          end
      end else if (cache_write) begin
          d_valid[index] = 1;  
      end
  end

  assign cache_din = cpu_rw ? cpu_dout : mem_dout;
  always_ff@(posedge clk) begin
       if(cache_write) begin
            d_tags [index] <= tag;
            d_data [index] = cache_din;
       end else begin
             d_tags [index] <= d_tags[index] + 32'd0;
             d_data [index] = d_data[index]  + 32'd0;
       end
  end  

  assign valid          = d_valid[index];
  assign d_tag_out      = d_tags [index];
  assign cache_dout     = d_data [index];

  assign cache_hit      = cpu_strobe & valid & (d_tag_out == tag);
  assign cache_miss     = cpu_strobe & (!valid | (d_tag_out != tag)); 
  assign mem_din        = cpu_dout;
  assign mem_addr       = cpu_addr;
  assign mem_rw         = cpu_rw;
  assign mem_strobe     = cpu_strobe | cache_miss;
  assign cpu_ready      = ~cpu_rw & cache_hit | (cache_miss | cpu_rw) & mem_ready; 
  assign cpu_din        = cache_hit ? cache_dout : mem_dout;
  assign d_data_dout    = cache_dout;
endmodule

